-- Schema for Domain: broadcast | Business: Sports Entertainment | Version: v1_mvm
-- Generated on: 2026-05-09 04:52:08

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `sports_entertainment_ecm`.`broadcast` COMMENT 'Media rights and distribution domain managing broadcast schedules, regional sports networks (RSN), OTT/IPTV streaming platforms, PPV event packaging, content delivery networks (CDN), and rights agreements. Owns media asset metadata, live feed distribution, blackout rules, DRM policies, replay content, and multi-platform delivery including linear TV and DTC streaming services. Critical for revenue generation through media rights deals.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`media_rights_deal` (
    `media_rights_deal_id` BIGINT COMMENT 'Unique surrogate identifier for the media rights deal record in the broadcast domain. Primary key for the media_rights_deal data product.',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: Media rights deals create specific compliance obligations (anti-piracy, content quotas, watershed rules, data privacy requirements per territory). Compliance teams must map each rights deal to its gov',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Franchise-level media rights deals (RSN local broadcast agreements) are a named business construct in sports. Local market rights are negotiated per franchise, and rights compliance reporting requires',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Rights fee revenue from media deals must post to a specific GL account (broadcast rights revenue) for P&L reporting and IFRS 15 compliance. Finance controllers map each deal to its revenue GL account ',
    `league_id` BIGINT COMMENT 'Reference to the sports league or governing body whose content is covered by this media rights deal (e.g., NFL, NBA, FIFA, MLS). Links to the league master data product.',
    `licensee_id` BIGINT COMMENT 'Foreign key linking to broadcast.licensee. Business justification: Media rights deals grant broadcast rights to licensees (the parties receiving the license). Every media rights deal must identify the licensee receiving the rights. This is essential for contract mana',
    `rights_holder_id` BIGINT COMMENT 'Foreign key linking to broadcast.rights_holder. Business justification: Media rights deals are negotiated with rights holders who own the content rights being licensed. Every media rights deal must identify the rights holder granting the rights. This is a foundational rel',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-scoped rights deal management and renewal scheduling require knowing which season a deal is anchored to. Rights deals often have season-specific terms, and rights expiry/renewal workflows are t',
    `annual_rights_fee_usd` DECIMAL(18,2) COMMENT 'Annual rights fee payable by the licensee in US Dollars. Used for ARR (Annual Recurring Revenue) tracking, financial planning in Workday Adaptive Planning, and year-over-year revenue comparison.',
    `blackout_rules_applicable` BOOLEAN COMMENT 'Indicates whether geographic or platform-based blackout rules apply to content distributed under this deal. When true, the CDN and streaming platform must enforce territory-based content restrictions.',
    `blackout_territory_codes` STRING COMMENT 'Comma-separated list of ISO 3166-1 alpha-3 country or market codes where content blackout restrictions apply under this deal. Used by CDN geo-restriction and OTT/IPTV platform access control engines.',
    `cdn_provider_name` STRING COMMENT 'Name of the CDN provider responsible for delivering digital content under this deal (e.g., Akamai, Fastly, Cloudflare). Relevant for OTT/IPTV and DTC streaming deals. Supports SLA monitoring and CDN cost allocation.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the deals contractual currency (e.g., USD, GBP, EUR). Required for multi-currency rights deals in international markets.. Valid values are `^[A-Z]{3}$`',
    `dalet_contract_ref` STRING COMMENT 'External reference identifier from Dalet Galaxy Media Asset Management system linking this deal to the corresponding rights contract object in the broadcast workflow system. Supports data lineage from source system.',
    `data_privacy_compliance_flag` BOOLEAN COMMENT 'Indicates whether the deal includes contractual data privacy compliance obligations (GDPR, CCPA) governing fan data collected through the licensees broadcast and streaming platforms.',
    `deal_created_timestamp` TIMESTAMP COMMENT 'Timestamp when this media rights deal record was first created in the system. Audit trail field for data governance and SOX compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `deal_name` STRING COMMENT 'Human-readable descriptive name of the media rights deal (e.g., NFL Sunday Ticket RSN Agreement FY2025). Used for identification in reporting and dashboards.',
    `deal_number` STRING COMMENT 'Externally-known alphanumeric contract reference number assigned by the rights management system (Dalet Galaxy or Salesforce CRM) and used in all correspondence with broadcast partners. Serves as the BUSINESS_IDENTIFIER for this agreement.',
    `deal_status` STRING COMMENT 'Current lifecycle state of the media rights deal. Drives rights enforcement and blackout rule activation. Values: draft, pending_approval, active, suspended, expired, terminated.. Valid values are `draft|pending_approval|active|suspended|expired|terminated`',
    `deal_type` STRING COMMENT 'Classification of the deal by distribution channel or platform type. Values: linear_tv (traditional broadcast), rsn (Regional Sports Network), ott (Over-The-Top Streaming), iptv (Internet Protocol Television), ppv (Pay-Per-View), dtc (Direct-To-Consumer). [ENUM-REF-CANDIDATE: linear_tv|rsn|ott|iptv|ppv|dtc — promote to reference product if additional types emerge]. Valid values are `linear_tv|rsn|ott|iptv|ppv|dtc`',
    `deal_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this media rights deal record was most recently modified. Supports change data capture (CDC) in the Databricks Silver Layer and audit trail requirements. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `deal_value_usd` DECIMAL(18,2) COMMENT 'Total gross contract value of the media rights deal in US Dollars over the full contract term. Represents the headline financial commitment. Used for EBITDA reporting and ARR calculations.',
    `digital_streaming_rights_included` BOOLEAN COMMENT 'Indicates whether OTT/IPTV digital streaming rights are included in this deal, permitting distribution via internet-based platforms (e.g., DTC apps, OTT services).',
    `dispute_resolution_mechanism` STRING COMMENT 'Contractually agreed mechanism for resolving disputes arising from this deal. cas_arbitration refers to the Court of Arbitration for Sport, applicable for international sports rights disputes.. Valid values are `arbitration|litigation|mediation|cas_arbitration`',
    `effective_date` DATE COMMENT 'Calendar date on which the media rights deal becomes legally binding and rights entitlements are enforceable. Aligns with contract commencement date in Salesforce CRM.',
    `exclusivity_type` STRING COMMENT 'Defines whether the rights granted are exclusive to the licensee within the territory, non-exclusive (shared with other licensees), first-window (first broadcast rights before others), or co-exclusive (shared exclusivity with a limited number of partners).. Valid values are `exclusive|non_exclusive|first_window|co_exclusive`',
    `execution_date` DATE COMMENT 'The date on which all parties formally signed and executed the media rights agreement. Distinct from effective_date (when rights begin) and deal_created_timestamp (when the record was created in the system).',
    `expiry_date` DATE COMMENT 'Calendar date on which the media rights deal expires and all rights entitlements cease. Nullable for perpetual or open-ended agreements. Critical for rights window enforcement and renewal planning.',
    `governing_law_country_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the jurisdiction whose laws govern this media rights agreement (e.g., USA, GBR, CHE). Determines applicable regulatory frameworks and dispute resolution venue.. Valid values are `^[A-Z]{3}$`',
    `highlights_rights_included` BOOLEAN COMMENT 'Indicates whether rights to produce and distribute short-form highlight clips are included in this deal. Relevant for social media, news broadcasts, and digital platform distribution.',
    `live_rights_included` BOOLEAN COMMENT 'Indicates whether live broadcast rights for events are included in this deal. Drives live feed distribution scheduling and OB (Outside Broadcast) resource allocation.',
    `max_events_per_season` STRING COMMENT 'Maximum number of events the licensee may broadcast per season under this deal. Caps the licensees broadcast entitlement and protects rights holders ability to distribute remaining events to other partners.',
    `min_guaranteed_events` STRING COMMENT 'Contractually guaranteed minimum number of live events the licensee is entitled to broadcast under this deal per contract year. Triggers make-good provisions if not met.',
    `payment_schedule_type` STRING COMMENT 'Defines the frequency and structure of rights fee payments from the licensee to the rights holder. Drives accounts receivable scheduling in SAP S/4HANA SD.. Valid values are `annual|semi_annual|quarterly|monthly|lump_sum`',
    `ppv_rights_included` BOOLEAN COMMENT 'Indicates whether Pay-Per-View event packaging rights are included in this deal, allowing the licensee to offer individual event purchases to consumers.',
    `renewal_notice_days` STRING COMMENT 'Number of calendar days prior to expiry_date by which either party must provide written notice of intent to renew or terminate. Drives automated renewal alert workflows in Salesforce CRM.',
    `renewal_option_type` STRING COMMENT 'Type of renewal option included in the deal. Automatic renewal triggers without action; mutual_agreement requires both parties to agree; right_of_first_refusal gives the licensee priority to match competing offers; none means no renewal option exists.. Valid values are `automatic|mutual_agreement|right_of_first_refusal|none`',
    `replay_rights_included` BOOLEAN COMMENT 'Indicates whether replay/rebroadcast rights are included in this deal, allowing the licensee to air recorded versions of events after the live window closes.',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'Percentage of net broadcast revenue shared back to the rights holder or league under the revenue share structure of this deal. Expressed as a decimal percentage (e.g., 15.00 = 15%). Critical for financial settlement calculations.',
    `rights_categories` STRING COMMENT 'Comma-separated list of rights categories included in this deal. Typical values: live, replay, highlights, ppv, clip_licensing, archive, digital_streaming, radio. Captures the full scope of content rights granted. [ENUM-REF-CANDIDATE: live|replay|highlights|ppv|clip_licensing|archive|digital_streaming|radio — promote to reference product]',
    `rights_window_count` STRING COMMENT 'Total number of distinct rights windows (time-period/platform/territory entitlement combinations) defined under this deal. Supports rights window enforcement and deal complexity classification.',
    `rsn_affiliate_code` BIGINT COMMENT 'Reference to the RSN affiliate entity associated with this deal when the deal type is rsn. Identifies the specific regional network carrying the broadcast rights within a defined geographic footprint.',
    `salesforce_opportunity_reference` STRING COMMENT 'External reference identifier from Salesforce CRM linking this media rights deal record to the originating CRM opportunity or contract object. Supports data lineage and system-of-record traceability.',
    `sport_name` STRING COMMENT 'Name of the sport covered by this media rights deal (e.g., American Football, Basketball, Soccer, Baseball, Hockey). Supports multi-sport deal classification and rights analytics.',
    `sublicensing_permitted` BOOLEAN COMMENT 'Indicates whether the licensee is contractually permitted to sublicense the media rights to third parties (e.g., regional affiliates, streaming sub-platforms). Critical for IP (Intellectual Property) protection and rights chain management.',
    `termination_for_cause_permitted` BOOLEAN COMMENT 'Indicates whether either party may terminate the deal early for cause (e.g., breach of contract, regulatory non-compliance, PED violations affecting league integrity). Relevant for compliance and legal risk management.',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code representing the primary geographic territory in which the broadcast rights are granted. Use WLD for worldwide deals. Drives blackout rule enforcement and CDN geo-restriction.. Valid values are `^[A-Z]{3}$`',
    `territory_scope` STRING COMMENT 'Categorical scope of the geographic territory covered by this deal. Distinguishes between national, regional (e.g., RSN footprint), local market, worldwide, or multi-territory agreements.. Valid values are `national|regional|local|worldwide|multi_territory`',
    CONSTRAINT pk_media_rights_deal PRIMARY KEY(`media_rights_deal_id`)
) COMMENT 'Master record of media rights agreements with broadcast partners (RSN, OTT, linear TV networks), including granular rights window definitions. Captures rights holder, territory, sport/league, exclusivity type, deal value, contract term, revenue share structure, rights categories (live, replay, highlights, PPV), and per-window platform/territory/time-period entitlements with sublicensing permissions. SSOT for all broadcast rights ownership, licensing terms, and rights window enforcement. Sourced from Dalet Galaxy and Salesforce CRM.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`broadcast_schedule` (
    `broadcast_schedule_id` BIGINT COMMENT 'Unique surrogate identifier for each broadcast schedule entry in the Dalet Galaxy broadcast workflow system. Primary key for the broadcast_schedule data product.',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel or platform (linear TV, OTT, IPTV, RSN) on which this schedule entry is assigned for distribution. Sourced from the content platform channel registry.',
    `competition_round_id` BIGINT COMMENT 'Foreign key linking to event.competition_round. Business justification: Broadcast schedules are structured around competition rounds — playoff quarterfinals, semifinals, and finals each have dedicated broadcast schedule blocks with distinct rights and programming. Broadca',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Sponsorship deals specify broadcast_mention_requirement obligations. The broadcast schedule is the operational record fulfilling those obligations. Linking enables compliance tracking of contractual b',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: RSN affiliate routing and local market blackout enforcement require knowing the home franchise for each scheduled broadcast. Role-prefix home_ distinguishes this from a generic franchise reference a',
    `league_schedule_id` BIGINT COMMENT 'Foreign key linking to league.schedule. Business justification: Broadcast operations teams map air schedules to the leagues official game schedule for rights compliance, production planning, and blackout enforcement. A sports-entertainment domain expert would exp',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Broadcast scheduling is organized by league season for rights compliance, season-level viewership reporting, and upfront ad sales planning. Every broadcast schedule entry belongs to a specific league ',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Broadcast scheduling for OTT and digital platforms requires mapping schedule entries to content platform channels to validate platform capabilities (resolution, DRM, ad insertion). Distribution planni',
    `playoff_bracket_id` BIGINT COMMENT 'Foreign key linking to league.playoff_bracket. Business justification: Playoff broadcasts require scheduling tied to specific bracket rounds and matchups for rights compliance, PPV pricing, and production planning. Broadcast schedulers must know which playoff bracket slo',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Broadcast schedules must reference the content compliance policy governing rating_classification, watershed rules, and accessibility mandates. Schedulers apply the applicable policy when configuring e',
    `fixture_id` BIGINT COMMENT 'Reference to the sporting or entertainment event being broadcast in this schedule window. Links the broadcast schedule to the event domain for event-to-channel assignment tracking.',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Broadcast schedules in regulated markets (FCC, Ofcom) must reference the regulatory filing authorizing each broadcast window. Compliance teams verify filing status before schedule activation; this lin',
    `rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: broadcast_schedule has rights_window_id → content.rights_window (cross-domain) but no FK to broadcast.broadcast_rights_window. The in-domain broadcast_rights_window is the authoritative record definin',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Broadcast schedules are organized around tournaments — tournament broadcast packages require schedule records at tournament level for EPG programming, rights window activation, and tournament-wide bro',
    `venue_id` BIGINT COMMENT 'Reference to the venue or facility from which this broadcast originates. Used for OB unit logistics, venue operations coordination, and geographic rights enforcement.',
    `actual_end_time` TIMESTAMP COMMENT 'Actual timestamp at which the broadcast feed concluded. Used alongside actual_start_time to compute true broadcast duration for rights compliance and billing reconciliation.',
    `actual_start_time` TIMESTAMP COMMENT 'Actual timestamp at which the broadcast feed went live or playback commenced. Compared against scheduled_start_time for on-time performance reporting and SLA compliance tracking.',
    `ad_break_count` STRING COMMENT 'Number of planned commercial advertisement breaks within this broadcast schedule entry. Used for sponsorship inventory management, ad sales planning, and revenue forecasting.',
    `ad_break_duration_minutes` STRING COMMENT 'Total planned duration of all commercial advertisement breaks in minutes for this broadcast schedule entry. Used for ad inventory capacity planning and sponsor commitment fulfillment tracking.',
    `air_date` DATE COMMENT 'Calendar date on which the broadcast is scheduled to air. Used for day-level scheduling, program guide publication, and rights window validation.',
    `audio_description_required` BOOLEAN COMMENT 'Indicates whether audio description (video description for visually impaired viewers) is required for this broadcast. Driven by FCC accessibility mandates and ADA compliance requirements for broadcast content.',
    `blackout_applicable` BOOLEAN COMMENT 'Indicates whether broadcast blackout rules apply to this schedule entry. When True, the blackout_rule_id and blackout_region_code must be evaluated before distribution to enforce territorial rights restrictions.',
    `broadcast_type` STRING COMMENT 'Classification of the broadcast feed type indicating whether the content is transmitted live, on a tape-delay basis, as a replay, as a highlight package, or as a Pay-Per-View (PPV) event. Drives rights enforcement, DRM policy application, and CDN routing logic.. Valid values are `live|tape_delay|replay|highlight|ppv`',
    `cdn_profile_code` STRING COMMENT 'Code identifying the Content Delivery Network (CDN) configuration profile used to distribute this broadcast. Determines routing, caching, and failover behavior for digital platform delivery.',
    `closed_caption_required` BOOLEAN COMMENT 'Indicates whether closed captioning is required for this broadcast schedule entry. Mandatory for FCC compliance under the Twenty-First Century Communications and Video Accessibility Act (CVAA) and ADA accessibility requirements.',
    `commentary_language_code` STRING COMMENT 'ISO 639-1/639-2 language code for the commentary/play-by-play audio track, which may differ from the primary broadcast language. Relevant for international feed distribution and multi-language OTT packaging.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this broadcast schedule record was first created in the Dalet Galaxy system and ingested into the Silver Layer. Supports audit trail, data lineage, and SOX financial controls compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the PPV price and any associated financial values on this schedule entry (e.g., USD, GBP, EUR). Required for multi-currency international broadcast markets.. Valid values are `^[A-Z]{3}$`',
    `feed_format` STRING COMMENT 'Technical broadcast feed format specifying the video quality standard for this schedule entry (e.g., HD, 4K, SD, HDR, VR). Used for CDN capacity planning, encoder assignment, and viewer experience reporting.. Valid values are `HD|4K|SD|HDR|VR`',
    `international_feed` BOOLEAN COMMENT 'Indicates whether this broadcast schedule entry uses an international feed (world feed) as opposed to a domestic production feed. Relevant for FIFA, IOC, and other international governing body rights distribution.',
    `language_code` STRING COMMENT 'ISO 639-1/639-2 language code for the primary audio track of this broadcast (e.g., en, es, fr-CA). Supports multi-language distribution and regional audience targeting.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `league_code` STRING COMMENT 'Code identifying the sports league or governing body associated with the event being broadcast (e.g., NFL, NBA, MLB, NHL, MLS, FIFA, UFC, ATP). Used for rights segmentation, league governance reporting, and audience analytics.',
    `ob_unit_code` STRING COMMENT 'Identifier for the Outside Broadcast (OB) truck or mobile production unit assigned to this broadcast schedule entry. Used for equipment scheduling, logistics coordination, and production cost allocation.',
    `platform_type` STRING COMMENT 'Category of the distribution platform for this broadcast schedule entry. Distinguishes linear TV, Over-The-Top (OTT) streaming, Internet Protocol Television (IPTV), Regional Sports Network (RSN), Direct-To-Consumer (DTC), and Pay-Per-View (PPV) platform delivery modes.. Valid values are `linear_tv|ott|iptv|rsn|dtc|ppv_platform`',
    `ppv_event` BOOLEAN COMMENT 'Indicates whether this broadcast schedule entry is a Pay-Per-View (PPV) event requiring individual purchase or access authorization. When True, triggers PPV pricing, access control, and revenue tracking workflows.',
    `ppv_price` DECIMAL(18,2) COMMENT 'Retail price charged to consumers for access to this Pay-Per-View (PPV) broadcast event. Applicable only when ppv_event is True. Used for revenue forecasting, pricing strategy analysis, and consumer billing.',
    `program_duration_minutes` STRING COMMENT 'Planned duration of the broadcast program in minutes as scheduled in the program guide. Used for slot allocation, ad break planning, and rights window compliance verification.',
    `rating_classification` STRING COMMENT 'Content rating classification assigned to this broadcast as per the TV Parental Guidelines system (e.g., TV-G, TV-PG, TV-14, TV-MA). Required for FCC compliance, parental control enforcement, and OTT platform content filtering.. Valid values are `TV-G|TV-PG|TV-14|TV-MA|TV-Y|TV-Y7`',
    `reference_code` STRING COMMENT 'Externally-known alphanumeric code assigned by Dalet Galaxy to uniquely identify this broadcast schedule entry across systems. Used for cross-system reconciliation and operational communication with broadcast partners.',
    `region_code` STRING COMMENT 'ISO 3166-1 alpha-3 country or territory code identifying the primary broadcast market for this schedule entry (e.g., USA, GBR, CAN). Used for rights territory enforcement, blackout rule application, and regional audience analytics.. Valid values are `^[A-Z]{3}$`',
    `rsn_affiliate_code` STRING COMMENT 'Code identifying the Regional Sports Network (RSN) affiliate carrying this broadcast. Applicable for regional distribution entries. Used for affiliate rights tracking, revenue sharing calculations, and regional audience reporting.',
    `schedule_status` STRING COMMENT 'Current lifecycle state of the broadcast schedule entry within the Dalet Galaxy workflow. Drives operational readiness and downstream distribution actions. [ENUM-REF-CANDIDATE: draft|confirmed|on_air|completed|cancelled|postponed — promote to reference product if additional states are required]. Valid values are `draft|confirmed|on_air|completed|cancelled|postponed`',
    `scheduled_end_time` TIMESTAMP COMMENT 'Precise date and timestamp at which the broadcast window is scheduled to conclude, including timezone offset. Used for slot duration calculation, back-to-back scheduling, and CDN resource planning.',
    `scheduled_start_time` TIMESTAMP COMMENT 'Precise date and timestamp at which the broadcast window is scheduled to begin, including timezone offset. Principal real-world event time for this schedule entry. Stored in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX).',
    `simulcast_flag` BOOLEAN COMMENT 'Indicates whether this broadcast schedule entry is a simultaneous multi-platform broadcast (simulcast) airing on multiple channels or platforms at the same time. Used for rights management and audience deduplication in ratings reporting.',
    `sport_type` STRING COMMENT 'Category of sport or entertainment content being broadcast (e.g., American Football, Basketball, Soccer, Baseball, Hockey, Tennis, MMA, Concert). Used for content classification, audience segmentation, and rights categorization. [ENUM-REF-CANDIDATE: american_football|basketball|soccer|baseball|hockey|tennis|mma|concert|other — promote to reference product]',
    `time_zone` STRING COMMENT 'IANA time zone identifier for the primary broadcast market (e.g., America/New_York, Europe/London). Required for accurate local air time display in program guides and blackout rule enforcement.',
    `title` STRING COMMENT 'Human-readable title of the broadcast schedule entry as it appears in the Dalet Galaxy workflow and on-air program guides. Typically includes event name, league, and broadcast type (e.g., NFL Sunday Night Football — Live).',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this broadcast schedule record was last modified in the source system or Silver Layer. Used for change detection, incremental data loading, and audit trail maintenance.',
    CONSTRAINT pk_broadcast_schedule PRIMARY KEY(`broadcast_schedule_id`)
) COMMENT 'Operational schedule of all planned and confirmed broadcast windows across linear TV, OTT, IPTV, and RSN platforms. Tracks event-to-channel assignments, air time, time zone, blackout applicability, feed type (live, tape-delay, replay), and production assignments. Core operational backbone for broadcast distribution — every broadcast begins as a schedule entry. Sourced from Dalet Galaxy broadcast workflow.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`channel` (
    `channel_id` BIGINT COMMENT 'Primary key for channel',
    `category_id` BIGINT COMMENT 'Foreign key linking to content.content_category. Business justification: Each broadcast channel is classified by a primary content category (live sports, highlights, news) governing ad insertion rules, distribution tier, and rights acquisition scope. The existing plain-str',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Each broadcast channel is a cost center in finance — channel operations (transmission, staffing, licensing fees) are tracked per channel for budget management and P&L. A sports broadcast finance exper',
    `governing_body_id` BIGINT COMMENT 'Foreign key linking to compliance.governing_body. Business justification: Broadcast channels are regulated by specific governing bodies (FCC, Ofcom, CRTC). The governing_body table has a broadcast_regulatory_authority flag confirming this relationship. Compliance officers',
    `league_id` BIGINT COMMENT 'Foreign key linking to league.league. Business justification: League-dedicated channels (NFL Network, NBA TV) require a direct channel-to-league link for league-branded channel management and rights compliance reporting. league_code on channel is a denormalize',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Channels must operate under content compliance policies (watershed rules, parental controls, accessibility mandates). Channel configuration attributes (parental_rating, closed_caption_supported, conte',
    `profit_center_id` BIGINT COMMENT 'Foreign key linking to finance.profit_center. Business justification: Each broadcast channel generates revenue (subscriptions, ad sales) tracked in a dedicated profit center for segment reporting and EBITDA analysis. Finance uses channel-level profit centers for channel',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Broadcast channels must hold active regulatory filings (FCC license, Ofcom license, spectrum authorization) to operate legally. Channel compliance management requires reference to the specific regulat',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: RSN channels are franchise-specific (YES Network/Yankees, NESN/Red Sox). RSN channel-to-franchise assignment is a named business construct for local rights management. Role-prefix rsn_ reflects the ',
    `ad_insertion_enabled` BOOLEAN COMMENT 'Indicates whether dynamic ad insertion (DAI) is enabled for this channel. When True, the channel supports server-side or client-side ad insertion for CPM (Cost Per Mille) based advertising revenue. Critical for sponsorship and advertising revenue planning.',
    `audio_format` STRING COMMENT 'Audio encoding format delivered by this channel (e.g., stereo, 5.1 surround, Dolby Atmos). Used for broadcast technical compliance, production scheduling, and premium tier packaging.. Valid values are `stereo|5.1|7.1|Dolby_Atmos|mono`',
    `bitrate_kbps` STRING COMMENT 'Target or maximum video bitrate for this channel measured in kilobits per second (Kbps). Used for CDN bandwidth capacity planning, SLA definition, and quality tier differentiation between SD, HD, and 4K tiers.',
    `blackout_rule_code` STRING COMMENT 'Code identifying the blackout restriction rule set applied to this channel. Blackout rules restrict broadcast of specific events in defined geographic territories per league agreements (e.g., NFL, NBA, MLB local blackout policies). Enforced at the channel level for linear and OTT distribution.',
    `broadcast_format` STRING COMMENT 'Primary content delivery format of this channel. Live = real-time event broadcast; Replay = time-shifted full event replay; VOD (Video on Demand) = on-demand library content; Simulcast = simultaneous broadcast across multiple platforms; Highlights = short-form curated content.. Valid values are `live|replay|VOD|simulcast|highlights`',
    `channel_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the channel, used in rights agreements, scheduling systems, and Dalet Galaxy media asset management workflows. Serves as the natural key across operational systems.. Valid values are `^[A-Z0-9_-]{2,30}$`',
    `channel_name` STRING COMMENT 'Official human-readable name of the broadcast channel or distribution outlet (e.g., ESPN Regional Sports Network East, Sports Entertainment OTT HD). Used in scheduling, rights contracts, and fan-facing interfaces.',
    `channel_number` STRING COMMENT 'Logical channel number assigned by the platform operator or cable/satellite provider for linear channel lineup placement (e.g., channel 720 on DirecTV). Used for EPG (Electronic Program Guide) integration and subscriber navigation.',
    `channel_status` STRING COMMENT 'Current operational lifecycle status of the channel. Active = currently distributing content; Inactive = temporarily off-air; Suspended = distribution halted due to rights or compliance issue; Pending Launch = configured but not yet live; Decommissioned = permanently retired.. Valid values are `active|inactive|suspended|pending_launch|decommissioned`',
    `channel_type` STRING COMMENT 'Categorical classification of the channels distribution model. Linear = traditional scheduled broadcast; OTT (Over-The-Top) = internet streaming; IPTV (Internet Protocol Television) = managed IP delivery; DTC (Direct-To-Consumer) = owned streaming service; PPV (Pay-Per-View) = event-based purchase; RSN (Regional Sports Network) = regional linear affiliate.. Valid values are `linear|OTT|IPTV|DTC|PPV|RSN`',
    `closed_caption_supported` BOOLEAN COMMENT 'Indicates whether this channel supports closed captioning for accessibility compliance. Required for ADA (Americans with Disabilities Act) and FCC closed captioning mandates for broadcast channels serving US audiences.',
    `country_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code representing the primary country of broadcast license or registration for this channel (e.g., USA, GBR, CAN). Used for regulatory compliance, blackout rule enforcement, and rights territory mapping.. Valid values are `^[A-Z]{3}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this channel record was first created in the system, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides audit trail for data governance and lineage tracking.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the monthly_rights_fee and any financial amounts associated with this channel (e.g., USD, EUR, GBP). Required for multi-currency financial reporting and SAP S/4HANA FI integration.. Valid values are `^[A-Z]{3}$`',
    `decommission_date` DATE COMMENT 'Calendar date on which this channel was or is scheduled to be permanently decommissioned and removed from distribution. Nullable for active channels. Used for rights wind-down planning and regulatory notification.',
    `distribution_territory` STRING COMMENT 'The geographic territory or market in which this vendor is authorized to distribute the channel under this agreement. A single channel may have different vendors authorized for different territories (e.g., US West, EMEA, APAC).',
    `effective_from` DATE COMMENT 'The calendar date on which this distribution agreement between the channel and vendor becomes effective and the vendor is authorized to begin distribution.',
    `effective_until` DATE COMMENT 'The calendar date on which this distribution agreement expires or is scheduled to terminate. Null indicates an open-ended agreement.',
    `encoding_standard` STRING COMMENT 'Video encoding/compression standard used for this channels stream (e.g., H.264/AVC, H.265/HEVC, AV1). Determines device compatibility, CDN efficiency, and streaming quality at given bitrates.. Valid values are `H.264|H.265|AV1|MPEG-2|VP9`',
    `epg_code` STRING COMMENT 'External identifier used by Electronic Program Guide (EPG) data providers (e.g., Tribune Media, Gracenote) to reference this channel in scheduling and guide data feeds. Enables automated schedule ingestion and viewer guide population.',
    `frame_rate` DECIMAL(18,2) COMMENT 'Video frame rate specification for this channel (e.g., 25fps for PAL markets, 30fps for NTSC markets, 60fps for premium sports HD). Impacts production compatibility, CDN bandwidth, and broadcast technical standards compliance.',
    `geographic_coverage` STRING COMMENT 'Textual description or structured list of geographic markets, regions, or territories this channel is licensed to serve (e.g., Northeast USA, Western Europe, Global excluding China). Distinct from country_code which captures the registration country; this field captures the full distribution footprint for rights enforcement.',
    `language_code` STRING COMMENT 'Primary broadcast language of the channel expressed as an ISO 639-1 or ISO 639-2 language code (e.g., en, es, fr-CA). Used for audience segmentation, rights territory management, and multi-language distribution planning.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this channel record, in ISO 8601 format with timezone offset (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change data capture (CDC), data lineage, and audit compliance.',
    `launch_date` DATE COMMENT 'Calendar date on which this channel was officially launched and made available to audiences. Used for channel lifecycle tracking, anniversary reporting, and rights agreement effective date alignment.',
    `max_concurrent_streams` STRING COMMENT 'Maximum number of simultaneous viewer streams permitted on this channel as defined by rights agreements or platform capacity constraints. Used for CDN capacity planning and rights compliance enforcement during peak events.',
    `monthly_rights_fee` DECIMAL(18,2) COMMENT 'Monthly fee paid to or received from the platform operator or rights holder for distribution of this channel, expressed in the channels billing currency. Confidential commercial term used for revenue management and EBITDA reporting.',
    `multiview_supported` BOOLEAN COMMENT 'Indicates whether this channel supports simultaneous multi-angle or multi-game viewing (multiview) for premium subscribers. A differentiating feature for OTT and DTC channels used in fan engagement and premium tier upsell strategies.',
    `ob_unit_required` BOOLEAN COMMENT 'Indicates whether this channel requires an OB (Outside Broadcast) unit for live event production. When True, triggers OB unit scheduling and resource allocation workflows in the broadcast operations team.',
    `parental_rating` STRING COMMENT 'Content parental advisory rating assigned to this channel per FCC and TV Parental Guidelines standards (e.g., TV-G, TV-PG, TV-14, TV-MA). Used for parental control enforcement, platform compliance, and audience targeting restrictions.. Valid values are `TV-G|TV-PG|TV-14|TV-MA|NR`',
    `platform_type` STRING COMMENT 'The technical platform or delivery mechanism through which this vendor distributes the channel under this agreement. Determines infrastructure requirements and may affect revenue share terms.',
    `ppv_enabled` BOOLEAN COMMENT 'Indicates whether this channel supports PPV (Pay-Per-View) event packaging and transactional purchase by viewers. When True, the channel can be used to distribute PPV events with individual purchase requirements rather than subscription access.',
    `resolution_tier` STRING COMMENT 'Video resolution quality tier offered by this channel. SD (Standard Definition), HD (High Definition), 4K (Ultra High Definition), 8K (Super Hi-Vision). Drives CDN (Content Delivery Network) bandwidth planning, rights packaging, and subscriber pricing tiers.. Valid values are `SD|HD|4K|8K`',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'The percentage of distribution revenue allocated to the vendor under this agreement. This is a commercially sensitive term unique to each channel-vendor distribution deal and cannot reside on either the channel or vendor master record.',
    `signal_type` STRING COMMENT 'Technical signal delivery mechanism for this channel. Determines infrastructure requirements, regulatory classification, and distribution partner compatibility. [ENUM-REF-CANDIDATE: digital|analog|IP|satellite|cable|terrestrial|fiber|microwave — promote to reference product]. Valid values are `digital|analog|IP|satellite|cable|terrestrial`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this channel record was originated or last updated (e.g., DALET for Dalet Galaxy MAM, SALESFORCE for Salesforce CRM). Used for data lineage, reconciliation, and Silver layer provenance tracking in the Databricks Lakehouse.. Valid values are `DALET|SALESFORCE|SAP|MANUAL|ARCHTICS`',
    `stream_url` STRING COMMENT 'Primary ingest or origin stream URL for OTT, IPTV, or DTC channel types. Confidential as it represents a direct access endpoint to live feed infrastructure. Used by broadcast operations and CDN configuration teams.',
    `subscriber_count` BIGINT COMMENT 'Current number of active subscribers or authorized viewers for this channel. For OTT/DTC/IPTV channels, reflects platform subscription count. For linear channels, reflects reported household reach. Used for ARPU (Average Revenue Per User) calculation and rights fee negotiations.',
    `time_zone` STRING COMMENT 'IANA time zone identifier for the channels primary broadcast schedule reference (e.g., America/New_York, Europe/London). Used for EPG scheduling, live event timing, and blackout rule time-window enforcement.',
    `uptime_sla_pct` DECIMAL(18,2) COMMENT 'Contractually committed uptime percentage for this channel as defined in the SLA (Service Level Agreement) with the platform operator or CDN provider (e.g., 99.95). Used for operational performance monitoring and penalty clause management.',
    CONSTRAINT pk_channel PRIMARY KEY(`channel_id`)
) COMMENT 'Master catalog of all broadcast channels and distribution outlets managed by Sports Entertainment — including RSN affiliates, OTT streaming channels, IPTV feeds, linear TV networks, and DTC streaming services. Captures channel name, type (linear/OTT/IPTV/DTC), platform operator, geographic coverage, language, resolution tier (SD/HD/4K), and active status.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`blackout_rule` (
    `blackout_rule_id` BIGINT COMMENT 'Unique surrogate identifier for the blackout rule record in the broadcast rights management system.',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel or platform (linear TV, OTT, IPTV, RSN) on which this blackout rule is enforced. Links to the platform channel catalog.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Franchise territory blackout enforcement is a core named business process in sports broadcasting. Home market blackout rules are franchise-specific (applied when a franchises home game is not sold ou',
    `league_id` BIGINT COMMENT 'Foreign key linking to league.league. Business justification: Blackout rules are league-mandated policies (e.g., NFL blackout policy per CBA). Direct league reference on blackout_rule supports league-level blackout policy management and compliance reporting. le',
    `license_id` BIGINT COMMENT 'Foreign key linking to content.content_license. Business justification: Blackout rules are mandated by specific content licenses that restrict distribution in certain territories or windows. Rights enforcement and dispute resolution teams must trace which content license ',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the media rights agreement that mandates or authorizes this blackout rule. Links the rule to its contractual basis.',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.obligation. Business justification: Blackout rules are derived from compliance obligations (league territorial exclusivity obligations, regulatory blackout mandates). Linking blackout_rule to obligation enables compliance teams to trace',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Blackout rules must be enforced on specific OTT/digital platform channels, not just linear broadcast channels. Rights enforcement teams need to identify which platform_channel is subject to a blackout',
    `fixture_id` BIGINT COMMENT 'Reference to the specific event (game, match, concert, PPV event) to which this blackout rule applies. Null if the rule applies to all events under a league or rights window.',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Sports blackout rules are frequently mandated by regulatory filings (FCC sports blackout regulations, territorial exclusivity filings). The blackout_rule references the regulatory filing that mandates',
    `rights_holder_id` BIGINT COMMENT 'Foreign key linking to broadcast.rights_holder. Business justification: Blackout rules are contractual obligations mandated by rights holders to protect territorial exclusivity and ticket sales. Every blackout rule must identify which rights holder mandated the restrictio',
    `rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: blackout_rule has rights_window_id → content.rights_window (cross-domain) but no FK to broadcast.broadcast_rights_window. A blackout rule is derived from and governed by a specific broadcast rights wi',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Blackout rules are applied at tournament level — entire tournaments may be subject to territory-wide blackouts (e.g., host country blackouts during World Cup qualifying). Rights compliance teams enfor',
    `applies_to_highlights` BOOLEAN COMMENT 'Indicates whether this blackout rule also restricts distribution of highlight clips and short-form content derived from the blacked-out event.',
    `applies_to_replay` BOOLEAN COMMENT 'Indicates whether this blackout rule extends to replay, VOD (Video on Demand), and time-shifted viewing of the event content, in addition to the live broadcast.',
    `approval_date` DATE COMMENT 'The date on which this blackout rule was formally approved by the designated authority for operational enforcement.',
    `approved_by` STRING COMMENT 'Name or identifier of the individual or organizational role that formally approved this blackout rule for enforcement (e.g., VP Broadcast Rights, League Office - Media Committee).',
    `blackout_lift_condition` STRING COMMENT 'Narrative description of the condition(s) under which this blackout rule is automatically lifted or deactivated (e.g., Blackout lifted when 85% of venue capacity is sold 72 hours prior to event start).',
    `blackout_type` STRING COMMENT 'Classification of the blackout scope: local (home market territory), national (entire country), international (cross-border), rsn_exclusivity (Regional Sports Network exclusive window), ppv (Pay-Per-View event blackout), ott (Over-The-Top streaming platform blackout).. Valid values are `local|national|international|rsn_exclusivity|ppv|ott`',
    `blackout_window_hours` STRING COMMENT 'Number of hours before and/or after the event start time during which the blackout is enforced. Defines the temporal scope of the blackout window around the event.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this blackout rule record was first created in the broadcast rights management system.',
    `distribution_platform` STRING COMMENT 'The delivery platform type on which the blackout is enforced: linear_tv (traditional broadcast), ott (Over-The-Top streaming), iptv (Internet Protocol Television), rsn (Regional Sports Network), ppv (Pay-Per-View), dtc (Direct-To-Consumer), cable, satellite. [ENUM-REF-CANDIDATE: linear_tv|ott|iptv|rsn|ppv|dtc|cable|satellite — 8 candidates stripped; promote to reference product]',
    `effective_from` DATE COMMENT 'The calendar date from which this blackout rule becomes binding and enforceable, aligned with the rights agreement or league mandate start date.',
    `effective_until` DATE COMMENT 'The calendar date on which this blackout rule ceases to be enforceable. Null for open-ended rules that remain active until explicitly terminated.',
    `enforcement_mechanism` STRING COMMENT 'Technical method used to enforce the blackout rule: geo_ip_block (IP geolocation blocking), drm_token (DRM token restriction), cdn_restriction (CDN-level content blocking), access_control (platform access control list), manual (manual operator action), api_enforcement (API-level enforcement).. Valid values are `geo_ip_block|drm_token|cdn_restriction|access_control|manual|api_enforcement`',
    `geo_precision_level` STRING COMMENT 'Granularity of geographic enforcement for this blackout rule: country, state, dma (Designated Market Area), zip_code, city. Determines how precisely the blackout territory is defined and enforced.. Valid values are `country|state|dma|zip_code|city`',
    `last_reviewed_date` DATE COMMENT 'The most recent date on which this blackout rule was reviewed for accuracy, compliance alignment, and continued applicability by the rights management team.',
    `mandate_source` STRING COMMENT 'The originating source of the blackout mandate: league_cba (Collective Bargaining Agreement), rights_contract (media rights deal terms), regulatory (FCC or government regulation), venue_agreement (venue exclusivity clause), network_policy (broadcaster internal policy).. Valid values are `league_cba|rights_contract|regulatory|venue_agreement|network_policy`',
    `notes` STRING COMMENT 'Free-text field for broadcast operations staff to capture additional context, exceptions, or operational instructions related to this blackout rule that are not captured in structured fields.',
    `notification_lead_hours` STRING COMMENT 'Number of hours in advance that notification must be submitted to the relevant authority before the blackout rule is activated or lifted. Applicable when notification_required is True.',
    `notification_required` BOOLEAN COMMENT 'Indicates whether advance notification to the league office, rights holder, or regulatory body is required before activating or lifting this blackout rule.',
    `override_authority` STRING COMMENT 'The organizational role or body authorized to approve an override of this blackout rule: league_office, rights_holder, network_ops (Network Operations), legal, executive. Applicable only when override_eligible is True.. Valid values are `league_office|rights_holder|network_ops|legal|executive`',
    `override_eligible` BOOLEAN COMMENT 'Indicates whether this blackout rule can be overridden under specific conditions (e.g., emergency broadcast, league waiver, special event designation). True = override is permissible with authorization.',
    `penalty_clause` STRING COMMENT 'Description of contractual or regulatory penalties applicable if this blackout rule is violated or improperly enforced, as defined in the rights agreement or league mandate.',
    `post_event_blackout_hours` STRING COMMENT 'Number of hours after event conclusion during which the blackout remains enforced. Protects replay and VOD rights windows for RSN and rights holders.',
    `pre_event_blackout_hours` STRING COMMENT 'Number of hours prior to event start time during which the blackout is enforced. Used to protect live gate attendance and RSN exclusivity windows.',
    `rsn_exclusivity` BOOLEAN COMMENT 'Indicates whether this blackout rule is driven by RSN exclusivity rights. True = an RSN holds exclusive broadcast rights in the territory, triggering the blackout on competing platforms.',
    `rsn_partner_name` STRING COMMENT 'Name of the RSN partner holding exclusive broadcast rights that trigger this blackout (e.g., Bally Sports, MSG Network, ROOT Sports). Populated when rsn_exclusivity is True.',
    `rule_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this blackout rule, used in league governance documents, RSN contracts, and broadcast operations systems.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `rule_description` STRING COMMENT 'Detailed narrative description of the blackout rule, including its business rationale, contractual basis, and operational scope.',
    `rule_name` STRING COMMENT 'Human-readable name describing the blackout rule (e.g., NFL Home Market Local Blackout, RSN Exclusivity Window - Pacific Northwest).',
    `rule_status` STRING COMMENT 'Current lifecycle state of the blackout rule: active (currently enforced), inactive (not enforced), pending (awaiting activation), suspended (temporarily halted), expired (past effective period), draft (under review).. Valid values are `active|inactive|pending|suspended|expired|draft`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this blackout rule was sourced (e.g., DALET_GALAXY, MANUAL_ENTRY, LEAGUE_FEED). Supports data lineage in the Databricks Silver Layer.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `sport_type` STRING COMMENT 'The sport or entertainment category to which this blackout rule applies (e.g., American Football, Basketball, Baseball, Hockey, Soccer, MMA, Concert). Enables cross-sport analytics and rule management.',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code or alpha-2 code identifying the primary geographic territory to which this blackout rule applies (e.g., USA, CAN, GBR).. Valid values are `^[A-Z]{2,3}$`',
    `territory_region` STRING COMMENT 'Sub-national region, DMA (Designated Market Area), or RSN coverage zone within the territory where the blackout applies (e.g., New York DMA, Pacific Northwest RSN Zone). Complements territory_code for granular geographic enforcement.',
    `ticket_sales_threshold_pct` DECIMAL(18,2) COMMENT 'The minimum percentage of venue capacity that must be sold for the blackout to be lifted (e.g., 85.00 means 85% of tickets must be sold). Applicable when trigger_condition is ticket_sales_threshold or sellout_rule.',
    `trigger_condition` STRING COMMENT 'The business condition that activates this blackout rule: ticket_sales_threshold (blackout lifted when ticket sales meet threshold), rsn_exclusivity (RSN holds exclusive rights), league_mandate (governing body requirement), rights_agreement (contractual obligation), ppv_purchase (PPV event requiring purchase), sellout_rule (event sold out). [ENUM-REF-CANDIDATE: ticket_sales_threshold|rsn_exclusivity|league_mandate|rights_agreement|ppv_purchase|sellout_rule|capacity_threshold|broadcast_window — promote to reference product]. Valid values are `ticket_sales_threshold|rsn_exclusivity|league_mandate|rights_agreement|ppv_purchase|sellout_rule`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp of the most recent modification to this blackout rule record, supporting audit trail and change management requirements.',
    `version_number` STRING COMMENT 'Incremental version number tracking amendments and revisions to this blackout rule over its lifecycle. Supports audit trail and change management for rights compliance.',
    CONSTRAINT pk_blackout_rule PRIMARY KEY(`blackout_rule_id`)
) COMMENT 'Business rules governing broadcast blackouts by territory, event, channel, and rights agreement. Captures blackout type (local, national, international), triggering conditions (ticket sales threshold, RSN exclusivity, league mandate), effective date range, override eligibility, and enforcement mechanism. Critical for rights compliance and RSN exclusivity protection. Sourced from league governance and media rights deal terms.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`live_feed` (
    `live_feed_id` BIGINT COMMENT 'Unique surrogate identifier for each live broadcast feed record in the Sports Entertainment broadcast domain. Primary key for the live_feed data product.',
    `backup_feed_id` BIGINT COMMENT 'Reference to the designated backup or failover live feed that will be activated if this primary feed fails. Enables automated failover management and redundancy tracking in broadcast operations.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: A live feed is distributed on a specific broadcast channel. While live_feed has boolean flags (is_ott_enabled, is_iptv_enabled, is_linear_tv_enabled), it lacks a direct FK to the channel master record',
    `production_id` BIGINT COMMENT 'Foreign key linking to broadcast.production. Business justification: A live feed is the technical output of a broadcast production. Linking live_feed to production enables crew, equipment, and production metadata to be associated with the feed. This supports post-event',
    `broadcast_schedule_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_schedule. Business justification: A live feed is produced for a specific broadcast schedule window. This FK links the operational feed record to its scheduled broadcast slot, enabling operational tracking of which feed serves which sc',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Live feeds incur significant costs (CDN delivery, OB unit operations, satellite uplinks) tracked against cost centers in finance. Finance requires live feed-to-cost-center linkage for production cost ',
    `asset_id` BIGINT COMMENT 'Identifier of the corresponding media asset record in the Dalet Galaxy Media Asset Management (MAM) system. Enables traceability between the operational live feed record and the media asset management workflow for ingest, archiving, and content repurposing.',
    `match_result_id` BIGINT COMMENT 'Foreign key linking to event.match_result. Business justification: Live feeds capture match results in real-time for result overlay graphics, post-match replay rights activation, and broadcast compliance verification. Broadcast operations teams link feed records to c',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the media rights agreement governing distribution of this live feed across licensed territories and platforms.',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Live feed OTT distribution requires referencing the content platform channel to configure CDN endpoints, DRM requirements, and geo-restriction rules. Feed engineers need this link to route live feeds ',
    `fixture_id` BIGINT COMMENT 'Reference to the scheduled sporting or entertainment event for which this live feed is being produced and distributed.',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Live feeds distributed across territories must be authorized by regulatory filings (spectrum licenses, content distribution authorizations). Operations teams verify regulatory filing status before act',
    `rights_window_id` BIGINT COMMENT 'Reference to the media rights agreement governing distribution of this live feed across licensed territories and platforms.',
    `venue_id` BIGINT COMMENT 'Reference to the source venue from which this live feed originates, used for routing and signal path management.',
    `actual_end_time` TIMESTAMP COMMENT 'Actual date and time (UTC) when this live feed concluded transmission. Used for post-event reporting, content ingest triggering, and broadcast duration billing. Null if feed is still active.',
    `actual_start_time` TIMESTAMP COMMENT 'Actual date and time (UTC) when this live feed began transmitting. Compared against scheduled_start_time to measure on-air punctuality and SLA (Service Level Agreement) compliance. Null if feed has not yet started.',
    `aspect_ratio` STRING COMMENT 'Width-to-height ratio of the video frame for this live feed. 16:9 is the standard widescreen format for HD and 4K broadcast; 4:3 is legacy SD format. Determines display compatibility across linear TV and OTT (Over-The-Top) platforms.. Valid values are `16:9|4:3|21:9|1:1`',
    `audio_format` STRING COMMENT 'Audio channel configuration and encoding format for the primary audio track of the live feed. Dolby Atmos and 7.1 surround are premium formats for high-end broadcast and streaming platforms.. Valid values are `stereo|5.1_surround|7.1_surround|mono|dolby_atmos`',
    `audio_track_count` STRING COMMENT 'Total number of discrete audio tracks embedded in the live feed. Multiple tracks support stereo, 5.1 surround, and separate commentary language channels. Relevant for multi-language broadcast distribution and accessibility compliance.',
    `bitrate_kbps` STRING COMMENT 'Target encoding bitrate of the live feed in kilobits per second (Kbps). Determines bandwidth consumption, CDN (Content Delivery Network) capacity requirements, and viewer quality of experience. Typical values range from 1,500 Kbps (SD) to 50,000+ Kbps (4K HDR).',
    `cdn_origin_endpoint` STRING COMMENT 'Primary CDN (Content Delivery Network) origin ingest URL or endpoint address from which the live feed is distributed to downstream delivery nodes and OTT (Over-The-Top) platforms. Core operational field for live distribution monitoring.',
    `commentary_language` STRING COMMENT 'ISO 639-1 or ISO 639-2 language code for the primary commentary audio track on this live feed (e.g., en for English, es for Spanish, fr for French). Drives regional distribution routing and RSN (Regional Sports Network) assignment.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when this live feed record was first created in the system, typically during pre-event broadcast planning. Supports audit trail, data lineage, and Silver Layer ingestion tracking.',
    `distribution_tier` STRING COMMENT 'Geographic scope of distribution authorized for this live feed under the applicable media rights agreement. Global feeds are distributed worldwide; regional feeds are limited to a geographic zone; national feeds are country-specific; local feeds are limited to a designated market area (DMA).. Valid values are `global|regional|national|local`',
    `encoding_format` STRING COMMENT 'Video codec standard used to compress and encode the live feed signal. H.264 (AVC) and H.265 (HEVC) are the dominant standards for broadcast and OTT (Over-The-Top) streaming delivery. Impacts bandwidth, quality, and platform compatibility.. Valid values are `H.264|H.265|AV1|MPEG-2|JPEG2000|ProRes`',
    `failover_activated` BOOLEAN COMMENT 'Indicates whether the backup or redundancy failover mechanism was triggered during this live feeds transmission. Used for post-event incident analysis, SLA (Service Level Agreement) reporting, and broadcast reliability KPI (Key Performance Indicator) tracking.',
    `failover_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when the failover mechanism was activated for this live feed. Null if failover_activated is false. Used for incident root cause analysis and SLA (Service Level Agreement) breach assessment.',
    `feed_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying this live feed within broadcast operations and Dalet Galaxy media asset management workflows. Used for signal routing, scheduling, and inter-system reference.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `feed_name` STRING COMMENT 'Human-readable descriptive name for the live feed, typically including event name, feed type, and language (e.g., NFL Championship - World Feed - English). Used in operational dashboards and scheduling systems.',
    `feed_status` STRING COMMENT 'Current operational lifecycle status of the live feed. Active indicates the feed is live and distributing; standby is ready but not transmitting; failed indicates a signal loss or error condition; backup indicates a redundancy feed has taken over; scheduled indicates pre-event readiness; terminated indicates the feed has ended.. Valid values are `active|standby|failed|backup|scheduled|terminated`',
    `feed_type` STRING COMMENT 'Classification of the live feed by its production and distribution purpose. World feed is the primary international signal; clean feed has no graphics; ISO feed is an isolated camera angle; PPV (Pay-Per-View) and OTT (Over-The-Top) feeds are platform-specific variants. [ENUM-REF-CANDIDATE: world_feed|clean_feed|commentary_feed|iso_feed|backup_feed|ppv_feed|ott_feed — promote to reference product]',
    `frame_rate` DECIMAL(18,2) COMMENT 'Number of video frames per second (fps) for this live feed. Common values include 25, 29.97, 50, 59.94, and 60 fps. Affects motion smoothness, storage requirements, and compatibility with broadcast standards across regions (PAL vs NTSC).',
    `hdr_format` STRING COMMENT 'High Dynamic Range (HDR) format applied to the live feed for enhanced color and brightness reproduction. HDR10 and HLG (Hybrid Log-Gamma) are the broadcast standards; Dolby Vision is a premium streaming format. None indicates standard dynamic range (SDR).. Valid values are `none|HDR10|HDR10+|HLG|Dolby_Vision`',
    `is_iptv_enabled` BOOLEAN COMMENT 'Indicates whether this live feed is authorized and configured for distribution via IPTV (Internet Protocol Television) networks, including managed IPTV services provided by telecommunications operators.',
    `is_linear_tv_enabled` BOOLEAN COMMENT 'Indicates whether this live feed is authorized and configured for distribution via traditional linear television broadcast channels, including RSN (Regional Sports Network) and national broadcast network affiliates.',
    `is_ott_enabled` BOOLEAN COMMENT 'Indicates whether this live feed is authorized and technically configured for distribution via OTT (Over-The-Top) streaming platforms, including DTC (Direct-To-Consumer) services and third-party streaming partners.',
    `is_ppv` BOOLEAN COMMENT 'Indicates whether this live feed is designated as a PPV (Pay-Per-View) event feed, requiring consumer purchase or entitlement before access is granted. Drives entitlement checks on DTC (Direct-To-Consumer) and OTT (Over-The-Top) platforms.',
    `latency_mode` STRING COMMENT 'Configured latency mode for this live feed delivery. Ultra-low latency (sub-3 seconds) is required for interactive and betting-adjacent use cases; low latency (3-10 seconds) for OTT (Over-The-Top) sports streaming; standard (10-30 seconds) for traditional broadcast; high for archive-quality delivery.. Valid values are `ultra_low|low|standard|high`',
    `ob_unit_code` STRING COMMENT 'Identifier of the Outside Broadcast (OB) truck or mobile production unit assigned to capture and produce this live feed at the source venue. Critical for resource scheduling and operational accountability.. Valid values are `^[A-Z0-9_-]{2,20}$`',
    `production_region` STRING COMMENT 'ISO 3166-1 alpha-3 country code of the primary production region where this live feed is originated and managed. Used for regulatory compliance, rights territory management, and broadcast operations routing.. Valid values are `^[A-Z]{3}$`',
    `redundancy_config` STRING COMMENT 'Redundancy architecture configured for this live feed to ensure continuity in case of primary signal failure. 1+1 means one active and one standby path; N+1 means N active feeds with one shared backup. Critical for broadcast SLA (Service Level Agreement) compliance.. Valid values are `none|1+1|2+1|n+1|full_mesh`',
    `replay_enabled` BOOLEAN COMMENT 'Indicates whether this live feed is authorized and configured to generate replay or catch-up content after the live event concludes. Drives post-event content ingest workflows in Dalet Galaxy and DRM (Digital Rights Management) policy application for replay windows.',
    `replay_window_hours` STRING COMMENT 'Number of hours after the live event ends during which replay content derived from this feed is available to authorized viewers. Defined by the media rights agreement and DRM (Digital Rights Management) policy. Null if replay_enabled is false.',
    `resolution` STRING COMMENT 'Video resolution tier of the live feed. SD (Standard Definition) is 480p/576p; HD (High Definition) is 720p; FHD (Full HD) is 1080p/1080i; 4K is 2160p; 8K is 4320p. Determines bandwidth requirements, CDN (Content Delivery Network) capacity planning, and platform delivery eligibility.. Valid values are `SD|HD|FHD|4K|8K`',
    `scheduled_start_time` TIMESTAMP COMMENT 'Planned date and time (UTC) when this live feed is scheduled to begin transmission. Used for broadcast scheduling, CDN (Content Delivery Network) pre-warming, and OB (Outside Broadcast) unit coordination.',
    `signal_type` STRING COMMENT 'Physical or logical transport medium used to carry the live feed signal from the source venue to the broadcast facility or CDN (Content Delivery Network) origin. Determines redundancy planning and SLA (Service Level Agreement) requirements.. Valid values are `satellite|fiber|ip|microwave|bonded_cellular`',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time (UTC) when this live feed record was most recently modified. Tracks operational changes such as status transitions, failover events, and configuration updates throughout the feed lifecycle.',
    CONSTRAINT pk_live_feed PRIMARY KEY(`live_feed_id`)
) COMMENT 'Operational record of each live broadcast feed produced and distributed for a scheduled event. Captures source venue, OB (Outside Broadcast) unit assignment, signal type (satellite, fiber, IP), encoding format (H.264/H.265), resolution (SD/HD/4K/8K), audio tracks, commentary language, feed status (active, standby, failed, backup), CDN origin endpoint, and redundancy configuration. Core operational entity for live broadcast production, distribution monitoring, and failover management.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`streaming_subscription` (
    `streaming_subscription_id` BIGINT COMMENT 'Unique surrogate identifier for each streaming subscription record. Primary key for the streaming_subscription data product within the broadcast domain.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: A streaming subscription grants access to a specific broadcast channel or service. streaming_subscription has platform and service_type (STRING) but no FK to the channel master record. This FK enables',
    `data_processing_record_id` BIGINT COMMENT 'Foreign key linking to compliance.data_processing_record. Business justification: Streaming subscriptions process fan personal data (viewing behavior, payment info, device data, geo-location) under GDPR/CCPA, requiring documented data processing records. The streaming_subscription ',
    `payment_method_id` BIGINT COMMENT 'Foreign key linking to fan.payment_method. Business justification: Streaming subscription recurring billing requires a reference to the fans stored tokenized payment method for charge processing, failed payment retry, and PCI compliance audit. streaming_subscription',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Franchise-specific streaming subscription packages (team OTT offerings, RSN digital subscriptions) are a named business construct. Knowing which franchise a subscription is associated with enables fra',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Streaming subscription revenue posts to a designated GL account (subscription revenue) for financial reporting. Revenue accounting teams assign GL accounts to subscription tiers during product setup —',
    `loyalty_program_id` BIGINT COMMENT 'Foreign key linking to fan.loyalty_program. Business justification: Streaming subscriptions are bundled with or earn points under specific loyalty programs (e.g., OTT subscribers auto-enroll in a digital loyalty tier). This link enables loyalty earning attribution per',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: A streaming subscription grants fan access to DTC/OTT content under a specific media rights deal. The deal governs the rights scope (digital_streaming_rights_included, ppv_rights_included, territory_c',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: A streaming subscription grants entitlement to a specific OTT/digital platform channel. Subscription management and entitlement enforcement systems require this link for access control, churn analysis',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Streaming subscriptions must comply with data privacy and consumer protection policies (GDPR consent, CCPA opt-out, auto-renewal disclosure laws). Subscription management references the applicable com',
    `fan_profile_id` BIGINT COMMENT 'Reference to the fan/subscriber identity record in the fan domain. Links the subscription to the individual consumer. Aligns with Adobe Experience Platform fan profile.',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-pass streaming subscription management and auto-renewal processing require season scoping. Annual season passes are a primary streaming product in sports; billing cycles, access windows, and re',
    `acquisition_channel` STRING COMMENT 'The marketing or distribution channel through which the subscriber was acquired. Used for CAC (Customer Acquisition Cost) attribution, ROI (Return on Investment) analysis, and channel performance reporting in Adobe Experience Platform. [ENUM-REF-CANDIDATE: organic|paid_search|social_media|email|partner|in_app|referral — 7 candidates stripped; promote to reference product]',
    `auto_renewal_flag` BOOLEAN COMMENT 'Indicates whether the subscription is configured to automatically renew at the end of each billing cycle without requiring explicit subscriber action. True = auto-renew enabled; False = subscription will expire at end_date unless manually renewed.',
    `billing_cycle` STRING COMMENT 'The recurring billing frequency for the subscription. Determines how often the subscriber is charged and when renewal events are triggered in the billing system.. Valid values are `monthly|quarterly|semi_annual|annual`',
    `billing_cycle_day` STRING COMMENT 'The day of the month (1–28) on which the recurring billing charge is processed. Used by the billing engine to schedule charge attempts and generate invoices.',
    `blackout_region_code` STRING COMMENT 'ISO country or region code identifying the geographic blackout restriction applied to this subscription. Enforces broadcast rights agreements and RSN (Regional Sports Network) territorial exclusivity. Null if no blackout applies.. Valid values are `^[A-Z]{2,3}$`',
    `cancellation_date` DATE COMMENT 'The date on which the subscriber initiated cancellation of the subscription. Distinct from end_date (which is the access expiry). Null if subscription has not been cancelled. Used for churn analysis and GDPR Article 17 right-to-erasure workflows.',
    `cancellation_reason` STRING COMMENT 'Subscriber-provided or system-inferred reason for cancellation. Used for churn root-cause analysis, content investment decisions, and win-back campaign targeting. Null if subscription is not cancelled. [ENUM-REF-CANDIDATE: price|content|technical|competitor|inactivity|payment_failure|other — 7 candidates stripped; promote to reference product]',
    `concurrent_stream_limit` STRING COMMENT 'Maximum number of simultaneous streams permitted under this subscription. Enforced by the streaming platform and CDN. Varies by plan tier (e.g., basic = 1, premium = 3, all-access = 5).',
    `consent_data_sharing_flag` BOOLEAN COMMENT 'Indicates whether the subscriber has consented to their viewing and behavioral data being shared with third-party analytics partners, sponsors, or league data programs. Required for GDPR Article 6 lawful basis and CCPA opt-out compliance.',
    `consent_marketing_flag` BOOLEAN COMMENT 'Indicates whether the subscriber has provided explicit consent to receive marketing communications related to their subscription and associated sports/entertainment content. Mandatory for GDPR and CCPA compliance in fan engagement workflows.',
    `consent_timestamp` TIMESTAMP COMMENT 'The timestamp at which the subscribers consent preferences (marketing and data sharing) were last captured or updated. Required for GDPR audit trail and proof-of-consent obligations.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp at which this streaming subscription record was first created in the system. Represents the RECORD_AUDIT_CREATED category for this MASTER_AGREEMENT entity. Used for data lineage, audit trails, and subscription cohort analysis.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which the subscription is billed (e.g., USD, GBP, EUR). Supports multi-market DTC/OTT operations across global territories.. Valid values are `^[A-Z]{3}$`',
    `device_code` STRING COMMENT 'Anonymized or hashed identifier of the primary device registered to this subscription. Used for device-binding enforcement under DRM policies and concurrent stream management. May be considered PII in certain jurisdictions.',
    `download_enabled_flag` BOOLEAN COMMENT 'Indicates whether the subscribers plan tier permits offline content downloads to their device. True = downloads permitted subject to DRM expiry rules; False = streaming only. Governed by content rights windows.',
    `drm_profile_code` STRING COMMENT 'Reference to the DRM (Digital Rights Management) policy profile assigned to this subscription tier. Governs content protection, concurrent stream limits, download rights, and device binding rules enforced by the CDN (Content Delivery Network) and streaming platform.',
    `end_date` DATE COMMENT 'The date on which the current subscription term ends. Nullable for open-ended subscriptions. For fixed-term plans this is the contractual expiry; for auto-renewing plans this is the next renewal date minus one day. Represents EFFECTIVE_UNTIL for this MASTER_AGREEMENT entity.',
    `geo_country_code` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code of the subscribers registered billing address. Used for geo-based rights enforcement, tax jurisdiction determination, GDPR/CCPA applicability, and regional content licensing compliance.. Valid values are `^[A-Z]{3}$`',
    `max_video_quality` STRING COMMENT 'The highest video resolution quality tier permitted under this subscription plan. Governs CDN (Content Delivery Network) stream quality caps and is a key differentiator between subscription tiers.. Valid values are `sd|hd|full_hd|uhd_4k`',
    `next_billing_date` DATE COMMENT 'The upcoming date on which the next recurring charge will be attempted for this subscription. Used for billing forecasting, dunning management, and subscriber communications.',
    `partner_bundle_code` STRING COMMENT 'Identifier of the third-party partner bundle or distribution agreement through which this subscription was provisioned (e.g., IPTV carrier bundle, telco partnership, OTT aggregator). Null for direct DTC subscriptions. Used for partner revenue share reporting.',
    `payment_method_type` STRING COMMENT 'The type of payment instrument used for recurring billing of this subscription. Stored as a tokenized reference type only — no raw card data is held in this product in compliance with PCI-DSS.. Valid values are `credit_card|debit_card|paypal|apple_pay|google_pay|direct_debit`',
    `plan_tier` STRING COMMENT 'The commercial tier of the streaming subscription defining the level of content access and features available to the subscriber. Tiers range from basic (limited content) to all-access (full DTC/OTT catalog including PPV events).. Valid values are `basic|standard|premium|all_access`',
    `ppv_access_flag` BOOLEAN COMMENT 'Indicates whether this subscription tier includes access to PPV (Pay-Per-View) events as part of the base plan entitlement. True = PPV events included; False = PPV requires separate purchase. Critical for revenue recognition and event packaging decisions.',
    `promo_code` STRING COMMENT 'The promotional or discount code applied at the time of subscription sign-up. Used to track campaign effectiveness, partner referral programs, and sponsorship-driven subscriber acquisition.',
    `promotional_rate` DECIMAL(18,2) COMMENT 'The discounted charge amount applied during a promotional period (e.g., introductory offer, bundle discount, loyalty reward). When populated, this rate overrides the standard subscription_charge for the promotional duration.',
    `promotional_rate_end_date` DATE COMMENT 'The date on which the promotional pricing expires and the subscriber reverts to the standard subscription_charge. Null if no promotion is active.',
    `service_type` STRING COMMENT 'Classifies the streaming service model under which this subscription operates. DTC (Direct-To-Consumer) = owned platform; OTT (Over-The-Top Streaming) = third-party app distribution; IPTV (Internet Protocol Television) = carrier-delivered; RSN (Regional Sports Network) = regional broadcast bundle; PPV (Pay-Per-View) = single-event purchase.. Valid values are `dtc|ott|iptv|rsn|ppv`',
    `source_system` STRING COMMENT 'The operational system of record from which this subscription record originated. Used for data lineage tracking, reconciliation, and Silver Layer provenance in the Databricks Lakehouse. Aligns with Adobe Experience Platform as the primary fan engagement and DTC subscription platform.. Valid values are `adobe_experience_platform|salesforce_crm|dtc_platform|ott_partner|manual`',
    `start_date` DATE COMMENT 'The date on which the subscription became or becomes effective and the subscriber gains access to entitled content. Represents the EFFECTIVE_FROM for this MASTER_AGREEMENT entity.',
    `subscription_charge` DECIMAL(18,2) COMMENT 'The gross recurring charge amount billed to the subscriber per billing cycle before any discounts or promotional adjustments. Expressed in the subscription currency.',
    `subscription_number` STRING COMMENT 'Externally-visible, human-readable subscription reference number used in customer communications, billing statements, and support interactions. Sourced from the DTC/OTT platform billing system.. Valid values are `^SUB-[A-Z0-9]{8,16}$`',
    `subscription_status` STRING COMMENT 'Current lifecycle state of the streaming subscription. Drives entitlement enforcement, billing actions, and fan engagement workflows. Active = currently billable and entitled; Trialing = within a free trial window; Suspended = temporarily paused; Cancelled = subscriber-initiated termination; Expired = end date passed without renewal.. Valid values are `active|suspended|cancelled|expired|pending|trialing`',
    `suspension_date` DATE COMMENT 'The date on which the subscription was placed into a suspended state (e.g., due to payment failure, voluntary pause, or compliance hold). Null if subscription has never been suspended.',
    `suspension_reason` STRING COMMENT 'The reason the subscription was placed into a suspended state. Used for operational triage, dunning management, and compliance reporting. Null if subscription has never been suspended.. Valid values are `payment_failure|voluntary_pause|fraud_review|compliance_hold|other`',
    `trial_end_date` DATE COMMENT 'The date on which the free trial period ends and the first paid billing cycle commences. Null if trial_flag is False. Critical for churn prediction and trial-to-paid conversion tracking.',
    `trial_flag` BOOLEAN COMMENT 'Indicates whether the subscription is currently within a free trial period. True = subscriber has not yet been charged; False = paid subscription. Used to distinguish trial cohorts from paying subscribers in ARPU (Average Revenue Per User) and LTV (Lifetime Value) analytics.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp at which this streaming subscription record was last modified. Used for change data capture (CDC) in the Databricks Silver Layer pipeline, audit trails, and detecting stale records.',
    CONSTRAINT pk_streaming_subscription PRIMARY KEY(`streaming_subscription_id`)
) COMMENT 'Master record of fan streaming subscriptions to DTC and OTT broadcast services. Captures subscriber reference, subscription plan tier (basic, premium, all-access), billing cycle, start/end dates, platform (mobile, web, connected TV), auto-renewal flag, promotional rate, and current status. SSOT for streaming subscription lifecycle within the broadcast domain. Complements fan domain identity records.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`media_asset` (
    `media_asset_id` BIGINT COMMENT 'Unique surrogate identifier for each media asset record in the broadcast domain master catalog. Primary key for the media_asset data product managed within Dalet Galaxy DAM.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Broadcast talent clearance and content rights management require knowing which athlete is featured in each media asset (highlight, interview, feature segment). Rights compliance, NIL conflict checks, ',
    `production_id` BIGINT COMMENT 'Foreign key linking to broadcast.production. Business justification: A media asset is produced by a broadcast production. media_asset has production_company (STRING) but no FK to the production record. Linking to production enables crew attribution, production metadata',
    `asset_id` BIGINT COMMENT 'Native asset identifier assigned by the Dalet Galaxy Digital Asset Management (DAM) system. Used to cross-reference records between the Silver Layer lakehouse and the operational DAM source system.',
    `data_processing_record_id` BIGINT COMMENT 'Foreign key linking to compliance.data_processing_record. Business justification: Media assets containing athlete biometric data, performance analytics, or fan-identifiable content trigger GDPR/CCPA data processing obligations. The asset must reference the data processing record go',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Broadcast media assets (master recordings, archive content) are capitalized as intangible fixed assets under IFRS/GAAP. The fixed_asset table has broadcast_rights_expiry_date confirming this use case.',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Franchise-level media asset licensing and highlight distribution rights management require a direct franchise reference. Team highlight packages sold to RSNs and franchise-branded content licensing ar',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Media assets are catalogued by league season for archive management, rights clearance, and content licensing decisions. season_year on media_asset is a denormalized representation of the season entity',
    `match_result_id` BIGINT COMMENT 'Foreign key linking to event.match_result. Business justification: Media assets (match recordings, highlight packages) are cataloged against specific match results for content rights management, archive retrieval, and post-production workflows. Content operations tea',
    `nil_agreement_id` BIGINT COMMENT 'Foreign key linking to athlete.nil_agreement. Business justification: Media assets featuring athletes in commercial or branded contexts must be cleared against the governing NIL agreement (broadcast_usage_rights, digital_usage_rights, rights_expiry_date). Rights clearan',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Media assets (recordings, highlights, replays) must comply with content policies governing age ratings, territorial distribution restrictions, and accessibility. Rights clearance workflows reference t',
    `fixture_id` BIGINT COMMENT 'Reference to the live sports or entertainment event that this media asset was captured from or is associated with. Links the broadcast asset to the event domain for scheduling, venue, and competition context.',
    `rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: A media assets distribution is governed by a broadcast rights window defining permitted territories, platforms, and time periods. media_asset has rights_territory and rights_expiry_date as denormaliz',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Tournament-level media assets (opening ceremonies, trophy presentations, tournament highlight reels) require direct tournament reference for content rights management, archive organization, and tourna',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the media asset passed quality control review and was approved for distribution. Marks the transition from qc_review to approved status in the broadcast workflow lifecycle.',
    `archive_location` STRING COMMENT 'Physical or logical storage path/URI where the media asset master file is archived (e.g., cloud object storage bucket path, SAN mount point, tape library reference). Used by the Dalet Galaxy DAM for asset retrieval and restore operations.',
    `archive_tier` STRING COMMENT 'Storage tier classification for the media asset based on access frequency and retention requirements. Hot: frequently accessed active assets; Warm: recent but less active; Cold: infrequently accessed; Deep Archive: long-term preservation. Drives storage cost allocation and retrieval SLA.. Valid values are `hot|warm|cold|deep_archive`',
    `aspect_ratio` STRING COMMENT 'Video aspect ratio of the media asset. Determines display compatibility across broadcast, OTT, and social media platforms. 16:9 is standard for HD/4K broadcast; 9:16 for vertical social media clips.. Valid values are `16:9|4:3|21:9|1:1|9:16`',
    `asset_status` STRING COMMENT 'Current state of the media asset within the Dalet Galaxy broadcast workflow lifecycle. Controls downstream distribution eligibility and archive processing. Values: draft (being created), ingest (being ingested), qc_review (under quality control review), approved (cleared for distribution), archived (moved to long-term storage), deleted (logically removed).. Valid values are `draft|ingest|qc_review|approved|archived|deleted`',
    `asset_type` STRING COMMENT 'Classification of the media asset by its production and editorial purpose within the broadcast workflow. Drives rights clearance rules, distribution eligibility, and archive retention policies. [ENUM-REF-CANDIDATE: live_recording|highlight_reel|replay|promo|interstitial|documentary|clip|raw_feed|press_conference|interview — promote to reference product if additional types are required]. Valid values are `live_recording|highlight_reel|replay|promo|interstitial|documentary`',
    `audio_channels` STRING COMMENT 'Number of audio channels in the media asset (e.g., 2 for stereo, 6 for 5.1 surround, 8 for 7.1 surround). Required for broadcast playout compatibility and OTT audio track configuration.',
    `blackout_rule_applicable` BOOLEAN COMMENT 'Indicates whether broadcast blackout rules apply to this media asset. When True, the asset is subject to geographic blackout restrictions per league media rights agreements (e.g., NFL local market blackouts, RSN territorial restrictions). Drives CDN geo-blocking logic.',
    `broadcast_date` DATE COMMENT 'Date on which this media asset was first broadcast or made available to audiences. Used for rights window calculations, replay eligibility, and archive classification.',
    `cdn_delivery_url` STRING COMMENT 'Primary CDN-hosted URL for streaming or downloading this media asset. Used by OTT, IPTV, and DTC platforms to serve content to end users. May be a signed or tokenized URL depending on DRM policy.',
    `checksum` STRING COMMENT 'SHA-256 cryptographic checksum of the media asset master file. Used to verify file integrity during ingest, transfer, and archive operations. Ensures no corruption or unauthorized modification of broadcast master content.. Valid values are `^[a-fA-F0-9]{64}$`',
    `codec` STRING COMMENT 'Video codec used to encode the media asset (e.g., H.264, H.265/HEVC, AVC, ProRes 422). Critical for transcoding decisions, CDN delivery optimization, and OTT/IPTV platform compatibility.',
    `content_rating` STRING COMMENT 'Television content rating assigned to the media asset per FCC/TV Parental Guidelines (e.g., TV-G, TV-PG, TV-14, TV-MA). Required for broadcast compliance, parental control enforcement on OTT platforms, and advertising eligibility.. Valid values are `TV-G|TV-PG|TV-14|TV-MA|NR`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the media asset record was first created in the Dalet Galaxy DAM system and propagated to the Silver Layer lakehouse. Audit trail field for data lineage and compliance reporting.',
    `distribution_channel` STRING COMMENT 'Primary distribution channel for which this media asset is packaged or cleared. Drives platform-specific encoding, DRM policy selection, and rights window application. [ENUM-REF-CANDIDATE: linear_tv|ott|iptv|dtc|rsn|ppv|social_media|vod|syndication — promote to reference product if additional channels required]',
    `duration_seconds` STRING COMMENT 'Total playback duration of the media asset in seconds. Used for broadcast scheduling, rights window calculations, PPV packaging, and CDN bandwidth planning.',
    `file_size_mb` DECIMAL(18,2) COMMENT 'Physical file size of the media asset in megabytes. Used for storage capacity planning, archive cost allocation, and CDN transfer cost estimation.',
    `format` STRING COMMENT 'Technical container or wrapper format of the media asset file (e.g., MXF for broadcast master, MP4 for OTT/DTC delivery, HLS for adaptive streaming). Determines compatibility with CDN delivery and playout systems. [ENUM-REF-CANDIDATE: MP4|MXF|MOV|HLS|DASH|ProRes|DNxHD — 7 candidates stripped; promote to reference product]',
    `frame_rate` DECIMAL(18,2) COMMENT 'Video frame rate of the media asset expressed in frames per second (fps), e.g., 23.98, 25.00, 29.97, 50.00, 59.94. Required for broadcast standards compliance and playout scheduling.',
    `ingest_source` STRING COMMENT 'Origin source from which the media asset was ingested into the Dalet Galaxy DAM system. OB (Outside Broadcast) truck, studio feed, satellite uplink, file transfer, API ingest, or third-party delivery. Used for provenance tracking and quality control routing.. Valid values are `ob_truck|studio_feed|satellite|file_transfer|api_ingest|third_party`',
    `ingest_timestamp` TIMESTAMP COMMENT 'Date and time when the media asset was first ingested into the Dalet Galaxy DAM system. Marks the start of the asset lifecycle and is used for SLA tracking, audit trails, and archive retention calculations.',
    `is_live_recording` BOOLEAN COMMENT 'Indicates whether this media asset is a live or near-live recording captured during an active broadcast event, as opposed to a pre-produced or post-produced asset. Drives priority ingest workflows and real-time CDN distribution rules.',
    `language_code` STRING COMMENT 'Primary spoken/audio language of the media asset expressed as an ISO 639-1 or ISO 639-2 language code (e.g., en, es, fr, pt-BR). Drives regional distribution rights and localization workflows.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `league_code` STRING COMMENT 'Code identifying the professional league or governing body associated with the media asset (e.g., NFL, NBA, MLB, NHL, MLS, FIFA, UFC, ATP). Drives rights clearance rules, blackout policy application, and RSN distribution eligibility.',
    `metadata_tags` STRING COMMENT 'Comma-separated free-text metadata tags applied to the media asset for search, discovery, and content classification purposes within the Dalet Galaxy DAM (e.g., playoffs,overtime,game-winner,fourth-quarter). Supports AI/ML content recommendation and editorial search.',
    `ppv_eligible` BOOLEAN COMMENT 'Indicates whether this media asset is eligible for Pay-Per-View (PPV) packaging and monetization. When True, the asset may be included in PPV event bundles and premium access tiers.',
    `resolution` STRING COMMENT 'Video resolution classification of the media asset. Drives distribution tier eligibility (e.g., 4K for premium PPV, HD for standard broadcast, SD for legacy RSN feeds) and storage cost allocation.. Valid values are `SD|HD|FHD|4K|8K`',
    `rights_expiry_date` DATE COMMENT 'Date on which the media rights clearance for this asset expires. After this date, the asset must be withheld from distribution pending rights renewal. Critical for automated rights enforcement and compliance with media rights agreements.',
    `rights_territory` STRING COMMENT 'Geographic territory or territories in which this media asset is cleared for distribution, expressed as ISO 3166-1 alpha-3 country codes or a named territory group (e.g., USA, GBR, WORLDWIDE, EMEA). Drives blackout rule enforcement and regional RSN assignment.',
    `sport_type` STRING COMMENT 'Sport or athletic discipline associated with the media asset (e.g., American Football, Basketball, Soccer, Baseball, Hockey, Tennis, MMA). Used for rights segmentation, RSN assignment, and content discovery. [ENUM-REF-CANDIDATE: american_football|basketball|soccer|baseball|hockey|tennis|mma|golf|motorsport|olympics — promote to reference product]',
    `subtitle_available` BOOLEAN COMMENT 'Indicates whether closed captions or subtitles are available for this media asset. Required for ADA (Americans with Disabilities Act) compliance for broadcast content and OTT platform accessibility standards.',
    `title` STRING COMMENT 'Human-readable title of the media asset as catalogued in the DAM system (e.g., NBA Finals Game 7 Full Broadcast, Super Bowl LVIII Halftime Show Highlight Reel).',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when the media asset record was last modified in the source DAM system or Silver Layer. Used for incremental data pipeline processing, audit trails, and change data capture (CDC) workflows.',
    `version_number` STRING COMMENT 'Incremental version number of the media asset, incremented each time the asset is edited, re-encoded, or updated. Supports version control and ensures downstream systems consume the correct asset revision.',
    CONSTRAINT pk_media_asset PRIMARY KEY(`media_asset_id`)
) COMMENT 'Master catalog of broadcast media assets managed within the Dalet Galaxy DAM system. Captures asset ID, title, asset type (live recording, highlight reel, replay, promo, interstitial), format, duration, resolution, language, sport/league association, event association, rights clearance status, archive location, and metadata tags. SSOT for broadcast-owned media asset inventory distinct from content domain editorial assets.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`rights_window` (
    `rights_window_id` BIGINT COMMENT 'Unique surrogate identifier for each granular rights window record within the broadcast domain. Primary key for the broadcast_rights_window data product on the Databricks Silver Layer.',
    `channel_id` BIGINT COMMENT 'Foreign key linking to broadcast.channel. Business justification: A broadcast rights window defines rights for a specific channel or distribution outlet. broadcast_rights_window has platform_type (STRING) but no FK to the channel master record. This FK enables chann',
    `category_id` BIGINT COMMENT 'Reference to the content category classification governing what type of content is covered by this rights window (e.g., live match, highlight reel, documentary, PPV event).',
    `fiscal_period_id` BIGINT COMMENT 'Foreign key linking to finance.fiscal_period. Business justification: Rights windows map to fiscal periods for period-end deferred revenue calculations and revenue recognition close. Finance teams must identify which windows fall within each fiscal period to correctly r',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Franchise-level local broadcast rights windows (RSN exclusivity windows, home market windows) are a real named business construct. Local rights windows are franchise-anchored and require a direct fran',
    `league_id` BIGINT COMMENT 'Reference to the sports league or competition governing body whose content is covered by this rights window (e.g., NFL, NBA, FIFA, MLS). Enables league-level rights aggregation and reporting.',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Rights windows are scoped to specific league seasons for scheduling, rights compliance, and royalty calculation. season_year is a denormalized representation of the season entity. A direct FK to leagu',
    `licensee_id` BIGINT COMMENT 'Reference to the broadcaster, OTT platform, or network entity that has been granted the rights for this window (e.g., RSN, DTC streaming service, IPTV provider).',
    `media_rights_deal_id` BIGINT COMMENT 'Reference to the parent media rights deal from which this window is derived. Links the granular window record back to the overarching rights agreement.',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Rights windows define territory/exclusivity scope; compliance policies govern permissible content distribution in each territory (data privacy, content standards). Rights window configuration must ref',
    `fixture_id` BIGINT COMMENT 'Reference to a specific sporting event or fixture covered by this rights window. Nullable for deal-level windows that cover a season or content category rather than a single event.',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: A broadcast rights window covering a specific territory must be backed by a regulatory filing (e.g., Ofcom authorization, FCC license) in that jurisdiction. Rights window activation is contingent on c',
    `rights_holder_id` BIGINT COMMENT 'Reference to the organisation or party that holds the broadcast rights for this window (e.g., league, federation, production company). Supports rights enforcement and royalty attribution.',
    `advertising_rights_included` BOOLEAN COMMENT 'Indicates whether the licensee has the right to sell advertising inventory (e.g., CPM-based ad slots) within the broadcast under this rights window. Impacts revenue share calculations and sponsorship conflict management.',
    `blackout_applicable` BOOLEAN COMMENT 'Indicates whether broadcast blackout rules apply to this rights window. When True, the CDN and DRM layer must enforce geographic or platform-based blackout restrictions as defined in the associated blackout policy.',
    `broadcast_window_type` STRING COMMENT 'Classifies the role of this rights window within the overall broadcast schedule. Primary windows cover live or first-run broadcasts; secondary covers repeat broadcasts; catch-up covers time-shifted viewing; archive covers library content; preview covers promotional clips.. Valid values are `primary|secondary|catch_up|archive|preview`',
    `catchup_window_days` STRING COMMENT 'Number of days after the original broadcast during which the licensee may make the content available for catch-up or time-shifted viewing. Zero or null indicates no catch-up rights are granted.',
    `concurrent_stream_limit` STRING COMMENT 'Maximum number of simultaneous streams permitted under this rights window for OTT, IPTV, or DTC platforms. Null indicates no contractual limit. Enforced at the CDN and streaming platform layer to prevent rights overrun.',
    `conflict_resolution_status` STRING COMMENT 'Current status of any rights conflict resolution process for this window. Populated only when rights_conflict_flag is True. Tracks progression from detection through resolution or escalation to CAS arbitration.. Valid values are `none|pending_review|resolved|escalated`',
    `content_type` STRING COMMENT 'Classifies the nature of the content covered by this rights window. Distinguishes live broadcast rights from replay, highlight, documentary, PPV event, and magazine show rights, each carrying different fee structures and DRM policies.. Valid values are `live|replay|highlight|documentary|ppv_event|magazine_show`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this rights window record was first created in the system. Supports audit trail requirements under SOX financial controls and GDPR data lineage obligations.',
    `effective_from` DATE COMMENT 'The calendar date from which this rights window record is considered valid for business use. Supports slowly changing dimension (SCD) patterns on the Silver Layer and enables point-in-time rights queries.',
    `effective_until` DATE COMMENT 'The calendar date until which this rights window record is considered valid. Nullable for currently active records. Supports SCD Type 2 history management on the Databricks Silver Layer.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether the rights granted in this window are exclusive to the licensee within the defined territory and platform. True = exclusive; False = non-exclusive. Exclusive windows command premium rights fees and restrict sublicensing.',
    `language_code` STRING COMMENT 'ISO 639-1/639-2 language code specifying the language in which the content may be broadcast under this rights window (e.g., en, es, fr). Supports multi-language rights management for global markets.. Valid values are `^[a-z]{2,3}$`',
    `max_broadcast_count` STRING COMMENT 'The maximum number of times the content may be broadcast under this rights window. Null indicates unlimited broadcasts within the window period. Enforced by the DRM and broadcast scheduling systems.',
    `min_lead_time_hours` STRING COMMENT 'The minimum number of hours before the scheduled broadcast that the licensee must notify the rights holder or activate the content feed. Supports SLA (Service Level Agreement) compliance and OB (Outside Broadcast) logistics.',
    `notes` STRING COMMENT 'Free-text field for capturing additional contractual conditions, special provisions, or operational notes associated with this rights window that are not captured in structured fields (e.g., specific event carve-outs, force majeure clauses).',
    `payment_schedule_type` STRING COMMENT 'Defines the payment cadence for the rights fee associated with this window. Drives accounts receivable scheduling in SAP S/4HANA and cash flow forecasting in Workday Adaptive Planning.. Valid values are `upfront|annual|quarterly|per_event|milestone`',
    `resolution_tier` STRING COMMENT 'The maximum video resolution permitted for broadcast under this rights window (SD, HD, 4K, 8K). Higher resolution tiers typically command premium rights fees and require specific CDN and DRM capabilities.. Valid values are `sd|hd|4k|8k`',
    `revenue_share_pct` DECIMAL(18,2) COMMENT 'The percentage of broadcast revenue (e.g., subscription, PPV, advertising) that the licensee must remit to the rights holder under this window. Drives financial settlement and EBITDA reporting.',
    `rights_category` STRING COMMENT 'Broad classification of the rights type granted in this window. Distinguishes domestic broadcast rights from international, digital, mobile, radio, PPV (Pay-Per-View), and archive rights. [ENUM-REF-CANDIDATE: domestic|international|digital|mobile|radio|ppv|archive — promote to reference product]',
    `rights_conflict_flag` BOOLEAN COMMENT 'Indicates whether a rights conflict has been detected for this window (e.g., overlapping exclusivity with another window for the same content, platform, and territory). Triggers review workflow in the rights management system.',
    `rights_fee_allocation_pct` DECIMAL(18,2) COMMENT 'The percentage of the total parent deal rights fee allocated to this specific window. Enables proportional revenue recognition and financial reporting across multiple windows derived from a single deal.',
    `rights_fee_amount` DECIMAL(18,2) COMMENT 'The monetary value of the rights fee allocated to this specific window from the parent rights deal. Represents the portion of the total deal value attributable to this platform-territory-period combination. Used for revenue recognition and financial reporting.',
    `rights_fee_currency` STRING COMMENT 'ISO 4217 three-letter currency code for the rights fee amount (e.g., USD, GBP, EUR). Required for multi-currency rights deals across global markets.. Valid values are `^[A-Z]{3}$`',
    `source_system_code` STRING COMMENT 'Code identifying the operational system of record from which this rights window record was ingested (e.g., DALET_GALAXY, SAP_SD, SALESFORCE_CRM). Supports data lineage tracking on the Databricks Silver Layer.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `sublicensing_permitted` BOOLEAN COMMENT 'Indicates whether the licensee is contractually permitted to sublicense the broadcast rights to third parties within this window. Drives downstream rights conflict detection and IP (Intellectual Property) protection enforcement.',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 three-letter country code identifying the geographic territory in which this rights window is valid. Drives blackout rule enforcement and geo-restriction logic at the CDN layer.. Valid values are `^[A-Z]{3}$`',
    `territory_scope` STRING COMMENT 'Indicates the geographic breadth of the rights window beyond a single country code. Supports multi-territory deal structures where a single window covers a defined group of markets.. Valid values are `national|regional|local|global|multi_territory`',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this rights window record was last modified. Supports change data capture (CDC) pipelines on the Databricks Silver Layer and audit trail requirements under SOX.',
    `window_end` TIMESTAMP COMMENT 'The precise date and time (exclusive) after which the licensees broadcast rights under this window expire. Nullable for perpetual or open-ended windows. Critical for automated rights expiry enforcement.',
    `window_reference_code` STRING COMMENT 'Externally-known alphanumeric business identifier for this rights window, used in contracts, invoices, and rights management systems. Enables cross-system reconciliation with SAP S/4HANA and Dalet Galaxy.. Valid values are `^[A-Z0-9-]{4,30}$`',
    `window_start` TIMESTAMP COMMENT 'The precise date and time (inclusive) from which the licensee is permitted to broadcast content under this rights window. Used for real-time rights enforcement at the CDN and DRM layer.',
    `window_status` STRING COMMENT 'Current lifecycle state of the broadcast rights window. Drives rights enforcement logic: only active windows permit broadcast. Transitions follow deal negotiation and regulatory approval workflows.. Valid values are `active|pending|suspended|expired|terminated|draft`',
    CONSTRAINT pk_rights_window PRIMARY KEY(`rights_window_id`)
) COMMENT 'Granular rights window records derived from media rights deals, defining the specific time periods, platforms, and territories in which a rights holder may broadcast specific content. Captures rights deal reference, content category, platform type, territory, window start/end, exclusivity flag, sublicensing permission, and rights fee allocation. Enables precise rights enforcement at the content-platform-territory level.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`production` (
    `production_id` BIGINT COMMENT 'Primary key for production',
    `broadcast_schedule_id` BIGINT COMMENT 'Reference to the parent broadcast schedule entry that this production instance fulfills. Links physical production execution to the scheduled broadcast slot.',
    `budget_id` BIGINT COMMENT 'Foreign key linking to finance.budget. Business justification: Broadcast productions have approved finance budgets for crew, equipment, and venue costs. Finance maps each production to its budget line for production cost variance analysis and approval workflows. ',
    `capacity_config_id` BIGINT COMMENT 'Foreign key linking to venue.capacity_config. Business justification: Broadcast production crews require the venue capacity configuration (camera positions, bowl orientation, floor plan version) for OB unit placement and technical setup. This is a standard venue technic',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Broadcast productions (OB units, crew, equipment) generate costs tracked against cost centers in finance for production budget management and variance analysis. Finance requires production-to-cost-cen',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Productions include sponsor_billboard_count fulfilling sponsorship deal obligations. Linking enables tracking of which deals broadcast mention and billboard obligations a production fulfills — requir',
    `emergency_response_plan_id` BIGINT COMMENT 'Foreign key linking to security.emergency_response_plan. Business justification: Production safety planning: broadcast productions at venues must operate under the venues active emergency response plan. Production managers reference the plan for media blackout triggers, evacuatio',
    `facility_id` BIGINT COMMENT 'Foreign key linking to venue.facility. Business justification: Broadcast productions are physically staged at a specific facility whose broadcast_production_level, wifi_capacity_mbps, and infrastructure specs govern OB unit placement and signal routing. Productio',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Broadcast productions schedule specific athletes for on-air feature segments, player profiles, and pre/post-show appearances. Production teams must coordinate athlete availability, clearances, and NIL',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Production costs (crew, equipment, facilities) post to specific GL accounts for broadcast cost reporting. Production already has cost_center and budget links, but the direct GL account assignment is r',
    `nil_agreement_id` BIGINT COMMENT 'Foreign key linking to athlete.nil_agreement. Business justification: Broadcast productions must verify NIL agreement broadcast_usage_rights and in_venue_usage_rights before featuring an athlete in sponsor billboards or branded segments. This rights clearance checkpoint',
    `policy_id` BIGINT COMMENT 'Foreign key linking to compliance.policy. Business justification: Broadcast productions must adhere to content compliance policies governing accessibility mandates, language requirements, and broadcast standards. Production teams reference the applicable policy when',
    `fixture_id` BIGINT COMMENT 'Reference to the sporting or entertainment event being produced and broadcast. Connects production execution to the event domain.',
    `production_fixture_id` BIGINT COMMENT 'Reference to the sporting or entertainment event being produced and broadcast. Connects production execution to the event domain.',
    `production_order_id` BIGINT COMMENT 'Foreign key linking to content.production_order. Business justification: Broadcast productions are authorized and scoped by content production orders. Cost reconciliation, editorial approval workflows, and sponsor deliverable tracking require tracing which production_order',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Live productions in regulated broadcast markets require regulatory filings (event broadcast permits, spectrum authorizations). Production records reference the regulatory filing authorizing the broadc',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-level production budget planning and rights window compliance require knowing which season a production belongs to. Production budgets are allocated per season, and rights compliance audits are',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Broadcast productions are organized at tournament level — tournament broadcast packages, opening/closing ceremonies, and multi-match production plans require a tournament reference. Production budgeti',
    `venue_id` BIGINT COMMENT 'Reference to the venue or facility where the broadcast production is physically executed. Used for venue technical setup coordination.',
    `actual_end_timestamp` TIMESTAMP COMMENT 'Actual date and time the broadcast production concluded. Used for rights window compliance, overtime cost tracking, and post-event reporting.',
    `actual_start_timestamp` TIMESTAMP COMMENT 'Actual date and time the broadcast production went on-air or began active production. Compared against scheduled_start_timestamp for SLA compliance and post-event reporting.',
    `broadcast_language` STRING COMMENT 'Primary language of the broadcast commentary and production, expressed as an IETF BCP 47 language tag (e.g., en, es, fr, pt-BR). Drives market designation and rights distribution.. Valid values are `^[a-z]{2,3}(-[A-Z]{2})?$`',
    `cdn_origin_endpoint` STRING COMMENT 'URL or identifier of the Content Delivery Network (CDN) origin endpoint used to distribute the live or replay feed for this production. Supports multi-platform delivery and streaming SLA monitoring.',
    `color_analyst_name` STRING COMMENT 'Full name of the color analyst (expert commentator) assigned to this productions commentary team. Tracked for talent scheduling, contract compliance, and broadcast quality.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this broadcast production record was first created in the Dalet Galaxy system and ingested into the Silver layer. Supports audit trail and data lineage.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for the PPV price and any production cost amounts (e.g., USD, GBP, EUR). Null for non-monetary productions.. Valid values are `^[A-Z]{3}$`',
    `distribution_platform` STRING COMMENT 'Primary platform through which this production is distributed to audiences. linear_tv = traditional broadcast; ott = Over-The-Top streaming; iptv = Internet Protocol Television; ppv = Pay-Per-View; dtc = Direct-To-Consumer streaming; rsn = Regional Sports Network; radio = audio broadcast. [ENUM-REF-CANDIDATE: linear_tv|ott|iptv|ppv|dtc|rsn|radio — 7 candidates stripped; promote to reference product]',
    `equipment_manifest_reference` STRING COMMENT 'Reference code or document identifier for the equipment manifest associated with this production, listing all cameras, audio rigs, transmission equipment, and OB unit inventory. Sourced from Dalet Galaxy asset tracking.',
    `frame_rate` DECIMAL(18,2) COMMENT 'Video frame rate (frames per second) for this broadcast production (e.g., 29.97, 50, 59.94). Governs technical compatibility with distribution platforms and replay content processing.',
    `graphics_package_version` STRING COMMENT 'Version identifier of the on-screen graphics package (lower thirds, scoreboards, transitions, sponsor overlays) deployed for this production. Critical for brand consistency and sponsor compliance.',
    `is_ppv` BOOLEAN COMMENT 'Indicates whether this broadcast production is packaged and distributed as a Pay-Per-View (PPV) event, requiring individual purchase by viewers. Drives revenue recognition and DRM policy application.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this broadcast production record in the source system or Silver layer. Supports change tracking, SLA monitoring, and incremental ETL processing.',
    `market_designation` STRING COMMENT 'Geographic market or territory for which this production is designated (e.g., US-National, RSN-Northeast, UK, LATAM-Spanish). Governs blackout rules, rights windows, and distribution platform routing. [ENUM-REF-CANDIDATE: promote to reference product for standardized market codes]',
    `notes` STRING COMMENT 'Free-text operational notes entered by the production team in Dalet Galaxy, capturing special instructions, contingency plans, or event-specific considerations for this broadcast production.',
    `ob_unit_identifier` STRING COMMENT 'Identifier of the Outside Broadcast (OB) truck or mobile production unit deployed for remote productions. Null for studio-based productions. Critical for equipment logistics and vendor billing.',
    `play_by_play_announcer` STRING COMMENT 'Full name of the primary play-by-play announcer assigned to this productions commentary team. Key talent assignment tracked for scheduling, NIL compliance, and audience analytics.',
    `postshow_duration_minutes` STRING COMMENT 'Planned duration in minutes of the post-show segment following the main event broadcast. Used for crew scheduling, sponsor slot allocation, and runsheet planning.',
    `ppv_price` DECIMAL(18,2) COMMENT 'Retail price charged to consumers for access to this Pay-Per-View (PPV) broadcast production. Null for non-PPV productions. Used in revenue management and financial reporting.',
    `preshow_duration_minutes` STRING COMMENT 'Planned duration in minutes of the pre-show segment preceding the main event broadcast. Used for crew scheduling, sponsor slot allocation, and runsheet planning.',
    `production_code` STRING COMMENT 'Externally-known alphanumeric code assigned by Dalet Galaxy to uniquely identify this broadcast production instance across systems and workflows. Used in runsheets, crew calls, and equipment manifests.. Valid values are `^PRD-[A-Z0-9]{4,12}$`',
    `production_status` STRING COMMENT 'Current lifecycle state of the broadcast production instance within the Dalet Galaxy workflow. draft = initial planning; confirmed = crew and equipment locked; in_production = active pre-show or live execution; on_air = currently broadcasting; completed = post-production wrap; cancelled = production cancelled.. Valid values are `draft|confirmed|in_production|on_air|completed|cancelled`',
    `production_type` STRING COMMENT 'Classification of the broadcast production method. live = real-time event coverage; studio = studio-based production; remote_ob = Outside Broadcast (OB) unit at venue; tape_delay = recorded and broadcast later; highlight = post-event highlight package. [ENUM-REF-CANDIDATE: live|studio|remote_ob|tape_delay|highlight|ppv — promote to reference product if additional types emerge]. Valid values are `live|studio|remote_ob|tape_delay|highlight`',
    `replay_availability_timestamp` TIMESTAMP COMMENT 'Date and time when replay or VOD content for this production becomes available to viewers on designated platforms. Null if replay_content_available is false. Governs rights window compliance.',
    `replay_content_available` BOOLEAN COMMENT 'Indicates whether replay/VOD content will be made available following the live broadcast of this production. Drives post-production workflow initiation and rights window activation in the content domain.',
    `rsn_affiliate_code` STRING COMMENT 'Code identifying the Regional Sports Network (RSN) affiliate carrying this production for regional linear TV distribution. Null for national or OTT-only productions.',
    `scheduled_end_timestamp` TIMESTAMP COMMENT 'Planned date and time when the broadcast production is scheduled to conclude, including post-show segments. Used for rights window management and crew scheduling.',
    `scheduled_start_timestamp` TIMESTAMP COMMENT 'Planned date and time (with timezone offset) when the broadcast production is scheduled to begin, including pre-show setup. Principal business event timestamp for scheduling and rights window alignment.',
    `sideline_reporter_name` STRING COMMENT 'Full name of the sideline reporter assigned to this production. May be null for studio-only productions. Tracked for talent scheduling and credential management.',
    `signal_format` STRING COMMENT 'Technical broadcast signal format used for this production (e.g., HD, 4K, 8K, SD, HDR). Determines equipment requirements, CDN bandwidth allocation, and platform delivery specifications.. Valid values are `HD|4K|8K|SD|HDR`',
    `sponsor_billboard_count` STRING COMMENT 'Number of sponsor billboard/branding slots allocated within this productions broadcast runsheet. Used for sponsorship fulfillment tracking and CPM reporting.',
    `title` STRING COMMENT 'Human-readable title of the broadcast production (e.g., NFL Sunday Night Football – Week 12 – Chiefs vs Eagles). Used in scheduling systems, crew communications, and broadcast runsheets.',
    CONSTRAINT pk_production PRIMARY KEY(`production_id`)
) COMMENT 'Operational record of each broadcast production instance for a scheduled event, including crew and commentary team assignments. Captures production type (live, studio, remote OB), director, technical producer, production company, equipment manifest, venue technical setup, graphics package version, pre-show/post-show segments, production status, and commentary team composition (play-by-play, color analyst, sideline reporter) with language and market designations. Links broadcast schedule to physical production execution. Sourced from Dalet Galaxy broadcast workflow.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`audience_rating` (
    `audience_rating_id` BIGINT COMMENT 'Unique surrogate identifier for each audience rating measurement record in the broadcast domain. Primary key for the audience_rating data product.',
    `athlete_profile_id` BIGINT COMMENT 'Foreign key linking to athlete.athlete_profile. Business justification: Broadcasters and rights holders segment audience ratings by featured athlete to measure broadcast value, negotiate future rights fees, and set ad rates. Athlete-level ratings analytics (e.g., LeBron e',
    `broadcast_schedule_id` BIGINT COMMENT 'Reference to the scheduled broadcast window for which this audience measurement was captured. Links the rating record to the specific broadcast slot.',
    `channel_id` BIGINT COMMENT 'Reference to the broadcast channel or streaming platform on which the content was delivered (e.g., linear TV network, OTT service, RSN feed).',
    `data_processing_record_id` BIGINT COMMENT 'Foreign key linking to compliance.data_processing_record. Business justification: Audience rating measurement collects viewer demographic and behavioral data (demo_age_band, demo_gender, demo_income_band), triggering GDPR/CCPA data processing obligations. Ratings records must refer',
    `deal_id` BIGINT COMMENT 'Foreign key linking to sponsorship.deal. Business justification: Audience ratings validate GRP and impression delivery commitments specified in sponsorship deals. Linking enables deal performance reporting and guarantee reconciliation — a standard post-broadcast sp',
    `franchise_id` BIGINT COMMENT 'Foreign key linking to league.franchise. Business justification: Franchise-level audience ratings (Team X games average Y million viewers) are a standard sports broadcast metric used directly in rights renewal negotiations and franchise valuation. A domain expert',
    `live_feed_id` BIGINT COMMENT 'Foreign key linking to broadcast.live_feed. Business justification: Audience ratings measure viewership for a specific live feed. While audience_rating already links to broadcast_schedule, the direct link to live_feed enables feed-level audience measurement, supportin',
    `match_result_id` BIGINT COMMENT 'Foreign key linking to event.match_result. Business justification: Audience ratings are measured for specific match results — post-match ratings reports, advertiser delivery confirmation, and rights fulfillment analytics all require linking rating records to the matc',
    `media_asset_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_asset. Business justification: audience_rating has asset_id → content.asset (cross-domain) but no FK to broadcast.media_asset. The in-domain media_asset contains broadcast-specific metadata (resolution, format, rights) needed for a',
    `media_rights_deal_id` BIGINT COMMENT 'Foreign key linking to broadcast.media_rights_deal. Business justification: Audience ratings track guarantee fulfillment against media rights deals. The audience_guarantee_target and guarantee_met fields on audience_rating are deal-level contractual metrics — the deal specifi',
    `platform_channel_id` BIGINT COMMENT 'Foreign key linking to content.platform_channel. Business justification: Audience ratings are measured per delivery platform. Linking audience_rating to content.platform_channel enables platform-level ratings reporting, which is required for audience guarantee validation i',
    `asset_id` BIGINT COMMENT 'Reference to the content asset or media item that was broadcast during the measured window, enabling rights valuation and scheduling optimization.',
    `rights_window_id` BIGINT COMMENT 'Foreign key linking to broadcast.broadcast_rights_window. Business justification: Audience ratings are measured within specific broadcast rights windows. The rights window defines the time period (window_start, window_end), territory (territory_code), and content type (rights_categ',
    `season_id` BIGINT COMMENT 'Foreign key linking to league.season. Business justification: Season-level ratings aggregation is a core input to rights fee renewal negotiations and league revenue sharing reports. Rights holders and licensees require season-scoped ratings data to evaluate deal',
    `tournament_id` BIGINT COMMENT 'Foreign key linking to event.tournament. Business justification: Tournament-level audience ratings are aggregated for rights renewal negotiations, sponsor reporting, and broadcast deal valuation. Rights holders and licensees require tournament-level viewership data',
    `ama_viewers` BIGINT COMMENT 'Average Minute Audience — the average number of viewers watching at any given minute during the broadcast window. The industry-standard linear TV metric used for GRP (Gross Rating Point) calculation and advertiser CPM (Cost Per Mille) pricing.',
    `audience_guarantee_target` BIGINT COMMENT 'Contractually committed minimum audience size (total viewers) for this broadcast window as specified in the media rights or advertising agreement. Used for contractual audience guarantee reconciliation against actual total_viewers. Confidential as it reflects negotiated contract terms.',
    `avg_viewing_duration_mins` DECIMAL(18,2) COMMENT 'Average number of minutes each viewer spent watching the broadcast during the measurement window. Used for audience engagement analysis, content scheduling optimization, and streaming platform retention reporting.',
    `blackout_applied` BOOLEAN COMMENT 'Indicates whether a broadcast blackout rule was in effect for this territory during the measurement window. Blackout rules are contractual restrictions in media rights agreements that limit broadcast in specific markets. Affects audience measurement scope.',
    `broadcast_date` DATE COMMENT 'Calendar date of the broadcast window in yyyy-MM-dd format. Used for day-level scheduling analysis, weekly ratings aggregation, and contractual audience guarantee reconciliation.',
    `content_genre` STRING COMMENT 'Genre classification of the broadcast content (e.g., Live Sport, Sports News, Sports Documentary, Concert, Esports, Magazine Show). Used for scheduling optimization and audience segmentation analysis. [ENUM-REF-CANDIDATE: Live Sport|Sports News|Sports Documentary|Concert|Esports|Magazine Show|Highlights|Other — promote to reference product]',
    `cpm_rate` DECIMAL(18,2) COMMENT 'Cost Per Mille — the advertising rate charged per 1,000 viewers for this broadcast window, in the applicable currency. Used for advertiser rate card justification and media rights deal valuation. Confidential as it reflects negotiated commercial pricing.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this audience rating record was first ingested into the Silver Layer data product. Supports data lineage, audit trail, and SLA (Service Level Agreement) compliance for measurement data delivery.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to the CPM rate and any monetary values in this record (e.g., USD, GBP, EUR, AUD). Required for multi-territory rights valuation and financial reporting.. Valid values are `^[A-Z]{3}$`',
    `demo_age_band` STRING COMMENT 'Age band of the primary target demographic for this audience measurement record. Standard age groupings used by Nielsen and BARB for advertiser targeting and rate card segmentation (e.g., Adults 18-49 is the primary US broadcast demographic).. Valid values are `18-24|25-34|35-44|45-54|55-64|65+`',
    `demo_gender` STRING COMMENT 'Gender segment of the audience demographic breakdown for this measurement record. Used for targeted advertising rate card differentiation and sponsor demographic guarantee reporting.. Valid values are `Male|Female|All|Unknown`',
    `demo_income_band` STRING COMMENT 'Household income band of the measured audience segment (e.g., Under $50K, $50K-$100K, $100K-$150K, $150K+). Used for premium advertiser targeting and sponsorship package valuation. [ENUM-REF-CANDIDATE: Under $50K|$50K-$100K|$100K-$150K|$150K-$200K|$200K+ — promote to reference product]',
    `demo_viewers_count` BIGINT COMMENT 'Number of viewers within the specific demographic segment (age band, gender, income band) defined for this record. Enables granular demographic reporting for advertiser guarantee reconciliation.',
    `drm_protected` BOOLEAN COMMENT 'Indicates whether the broadcast content was delivered with DRM (Digital Rights Management) protection active during the measurement window. Relevant for OTT and IPTV platform compliance and piracy impact assessment on audience figures.',
    `frequency` DECIMAL(18,2) COMMENT 'Average number of times a unique viewer was exposed to the broadcast during the measurement period. Used alongside reach to calculate GRP (Gross Rating Point) and assess advertising campaign effectiveness.',
    `grp_value` DECIMAL(18,2) COMMENT 'Gross Rating Point value for this broadcast window, representing the sum of ratings across the target audience. Calculated as rating_pct multiplied by frequency. Primary currency for advertising inventory pricing and sponsorship valuation.',
    `guarantee_met` BOOLEAN COMMENT 'Indicates whether the actual audience (total_viewers) met or exceeded the contractual audience guarantee target for this broadcast window. Drives make-good advertising inventory decisions and rights agreement penalty calculations.',
    `live_viewers` BIGINT COMMENT 'Number of viewers who watched the broadcast in real-time (live) as opposed to time-shifted. Distinguishes live audience from time-shifted for PPV event reporting and live sports rights valuation.',
    `market_name` STRING COMMENT 'Name of the designated market area (DMA) or broadcast market within the territory (e.g., New York DMA, London ITV Region, Sydney Metro). Used for sub-national audience reporting and RSN rate card justification.',
    `measurement_methodology` STRING COMMENT 'The data collection methodology used by the measurement source. Panel-based (Nielsen People Meter, BARB panel) uses a representative sample; Census measures all streams; Hybrid combines panel and census; Modeled uses statistical estimation; Self-Reported uses platform-provided data.. Valid values are `Panel|Census|Hybrid|Modeled|Self-Reported`',
    `measurement_reference_code` STRING COMMENT 'Externally-known unique identifier assigned by the measurement provider (e.g., Nielsen panel ID, BARB survey code, OzTAM report reference, Comscore stream ID) for cross-system reconciliation.. Valid values are `^[A-Z0-9_-]{4,50}$`',
    `measurement_source` STRING COMMENT 'The third-party or internal system that provided the audience measurement data. Determines methodology, panel composition, and credibility for advertiser and rights negotiations. [ENUM-REF-CANDIDATE: Nielsen|BARB|OzTAM|Comscore|Internal Streaming Analytics|Other — promote to reference product if additional sources are onboarded]. Valid values are `Nielsen|BARB|OzTAM|Comscore|Internal Streaming Analytics|Other`',
    `measurement_status` STRING COMMENT 'Current lifecycle state of the audience rating record. Preliminary ratings are released within 24 hours; confirmed ratings are validated by the measurement provider; revised ratings incorporate late-reported data; final ratings are locked for contractual use; disputed ratings are under review.. Valid values are `preliminary|confirmed|revised|final|disputed`',
    `peak_concurrent_viewers` BIGINT COMMENT 'Maximum number of viewers simultaneously watching the broadcast at any single minute during the window. Key metric for streaming platform capacity planning, CDN (Content Delivery Network) provisioning, and PPV event valuation.',
    `rating_pct` DECIMAL(18,2) COMMENT 'Percentage of the total universe of TV households or individuals that watched the broadcast, regardless of whether their TV was on. Distinct from share_pct which is based only on those actively viewing. Used for GRP (Gross Rating Point) calculation.',
    `rating_type` STRING COMMENT 'Classification of the audience measurement metric captured in this record. GRP (Gross Rating Point) represents total delivery; CPM (Cost Per Mille) supports advertiser rate card justification; Reach measures unique audience; Frequency measures average exposures; AMA (Average Minute Audience) is the standard linear TV metric; Share is the percentage of viewing universe. [ENUM-REF-CANDIDATE: GRP|CPM|Reach|Frequency|Viewership|AMA|Share — promote to reference product]',
    `reach` BIGINT COMMENT 'Total number of unique individuals who viewed at least one minute of the broadcast during the measured window. Distinct from total_viewers which may count repeat viewing. Used for unduplicated audience reporting to sponsors and rights holders.',
    `reporting_period_type` STRING COMMENT 'Defines the time-shifted viewing window included in this measurement record per Nielsen and BARB standards. Live = real-time only; Live+1 includes same-day DVR; Live+3 includes 3-day playback; Live+7 includes 7-day playback; Live+35 is the C35 standard; VOD is on-demand only.. Valid values are `Live|Live+1|Live+3|Live+7|Live+35|VOD`',
    `share_pct` DECIMAL(18,2) COMMENT 'Percentage of the total viewing universe (all households/individuals with TV/streaming access) that watched this broadcast during the window. Expressed as a decimal percentage (e.g., 12.500 = 12.5%). Core metric for competitive scheduling analysis.',
    `sport_type` STRING COMMENT 'The sport or entertainment category of the broadcast content (e.g., NFL Football, NBA Basketball, FIFA Soccer, UFC MMA, Concert). Enables sport-specific audience trend analysis and rights valuation benchmarking. [ENUM-REF-CANDIDATE: NFL Football|NBA Basketball|MLB Baseball|NHL Hockey|MLS Soccer|FIFA Soccer|UFC MMA|Tennis|Concert|Other — promote to reference product]',
    `territory_code` STRING COMMENT 'ISO 3166-1 alpha-3 country code identifying the geographic territory in which the audience measurement was conducted. Critical for regional rights valuation, blackout rule enforcement, and RSN (Regional Sports Network) reporting.. Valid values are `^[A-Z]{3}$`',
    `time_shifted_viewers` BIGINT COMMENT 'Number of viewers who watched the broadcast on a time-shifted basis (DVR, catch-up, VOD replay) within the measurement window. Reported separately per Nielsen Live+3 and Live+7 standards for contractual audience guarantee reconciliation.',
    `total_viewers` BIGINT COMMENT 'Total number of individual viewers who watched the broadcast during the measured window. The primary headline metric used in media rights negotiations, advertiser rate cards, and contractual audience guarantees.',
    `universe_size` BIGINT COMMENT 'Total size of the viewing universe (total TV households or individuals) used as the denominator for rating_pct and share_pct calculations in the given territory and demographic. Provided by the measurement source.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this audience rating record was last modified, typically when preliminary ratings are revised or confirmed by the measurement provider. Supports audit trail and revised-rating reconciliation workflows.',
    `window_end_timestamp` TIMESTAMP COMMENT 'The precise date and time when the measured broadcast window ended. Combined with window_start_timestamp to define the exact measurement interval for AMA and share calculations.',
    `window_start_timestamp` TIMESTAMP COMMENT 'The precise date and time when the measured broadcast window began, in ISO 8601 format with timezone offset. Used as the principal business event timestamp for scheduling optimization and rights valuation.',
    CONSTRAINT pk_audience_rating PRIMARY KEY(`audience_rating_id`)
) COMMENT 'Transactional record of broadcast audience measurement data per scheduled broadcast window. Captures channel, territory, measurement source (Nielsen, BARB, OzTAM, Comscore, internal streaming analytics), rating type (GRP, CPM, reach, frequency, viewership), total viewers, demographic breakdown (age, gender, income), peak concurrent viewers, average minute audience (AMA), share percentage, and time-shifted viewing. Operational data used for rights valuation, advertiser rate card justification, scheduling optimization, and contractual audience guarantee reconciliation.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`rights_holder` (
    `rights_holder_id` BIGINT COMMENT 'Primary key for rights_holder',
    `parent_rights_holder_id` BIGINT COMMENT 'Self-referencing FK on rights_holder (parent_rights_holder_id)',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Rights holders operating in regulated broadcast markets must maintain active regulatory filings (content provider registrations, broadcast licenses). Rights holder onboarding and ongoing compliance ve',
    `bank_account_name` STRING COMMENT 'Name on the bank account used for payments to the rights holder.',
    `bank_account_number` STRING COMMENT 'Bank account number for remitting payments to the rights holder.',
    `bank_routing_number` STRING COMMENT 'Bank routing or transit number for the rights holder payment account.',
    `bank_swift_code` STRING COMMENT 'SWIFT/BIC code for international wire transfers to the rights holder.',
    `business_registration_number` STRING COMMENT 'Official business registration or incorporation number issued by the governing jurisdiction.',
    `content_category` STRING COMMENT 'Primary category or genre of content for which this rights holder typically controls media rights. [ENUM-REF-CANDIDATE: wrestling|boxing|mixed_martial_arts|live_events|concerts|sports|entertainment|documentary|reality — promote to reference product]',
    `contract_end_date` DATE COMMENT 'Date when the current master relationship or agreement with this rights holder expires or terminates.',
    `contract_start_date` DATE COMMENT 'Date when the master relationship or first agreement with this rights holder became effective.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the rights holder record was first created in the system.',
    `credit_rating` STRING COMMENT 'Credit rating assigned to the rights holder by recognized rating agencies for financial risk assessment.',
    `currency_code` STRING COMMENT 'Three-letter ISO currency code for the rights holder preferred payment currency.',
    `exclusivity_flag` BOOLEAN COMMENT 'Indicates whether this rights holder has exclusive rights to certain content or territories.',
    `headquarters_address_line1` STRING COMMENT 'Primary street address line for the rights holder headquarters location.',
    `headquarters_address_line2` STRING COMMENT 'Secondary address line for suite, floor, or building information at headquarters location.',
    `headquarters_city` STRING COMMENT 'City where the rights holder headquarters is located.',
    `headquarters_country_code` STRING COMMENT 'Three-letter ISO country code for the rights holder headquarters location.',
    `headquarters_postal_code` STRING COMMENT 'Postal or ZIP code for the rights holder headquarters location.',
    `headquarters_state_province` STRING COMMENT 'State or province where the rights holder headquarters is located.',
    `legal_entity_name` STRING COMMENT 'Official registered legal name of the rights holder entity as it appears in contracts and legal documents.',
    `minimum_guarantee_amount` DECIMAL(18,2) COMMENT 'Minimum guaranteed payment amount committed to this rights holder regardless of performance.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when the rights holder record was last modified or updated.',
    `notes` STRING COMMENT 'Additional notes, comments, or special instructions related to the rights holder relationship.',
    `payment_terms_days` STRING COMMENT 'Standard number of days for payment terms in agreements with this rights holder.',
    `preferred_payment_method` STRING COMMENT 'Preferred method of payment for rights fees and royalties to this rights holder.',
    `primary_contact_email` STRING COMMENT 'Primary email address for business communication with the rights holder organization.',
    `primary_contact_name` STRING COMMENT 'Full name of the primary business contact person at the rights holder organization.',
    `primary_contact_phone` STRING COMMENT 'Primary telephone number for contacting the rights holder organization.',
    `revenue_share_percentage` DECIMAL(18,2) COMMENT 'Standard revenue share percentage applicable to agreements with this rights holder.',
    `rights_holder_code` STRING COMMENT 'Unique business identifier or code assigned to the rights holder for operational reference and system integration.',
    `rights_holder_name` STRING COMMENT 'Full legal name of the rights holder organization or entity that owns or controls media rights.',
    `rights_holder_status` STRING COMMENT 'Current lifecycle status of the rights holder relationship indicating operational state.',
    `rights_holder_type` STRING COMMENT 'Classification of the rights holder entity based on organizational structure and business model.',
    `tax_identification_number` STRING COMMENT 'Government-issued tax identification number for the rights holder entity used for financial reporting and compliance.',
    `territory_scope` STRING COMMENT 'Geographic scope of rights typically held by this rights holder indicating the breadth of their territorial coverage.',
    `website_url` STRING COMMENT 'Official website URL for the rights holder organization.',
    CONSTRAINT pk_rights_holder PRIMARY KEY(`rights_holder_id`)
) COMMENT 'Master reference table for rights_holder. Referenced by rights_holder_id.';

CREATE OR REPLACE TABLE `sports_entertainment_ecm`.`broadcast`.`licensee` (
    `licensee_id` BIGINT COMMENT 'Primary key for licensee',
    `data_processing_record_id` BIGINT COMMENT 'Foreign key linking to compliance.data_processing_record. Business justification: Licensees that process subscriber/viewer data on behalf of the rights holder act as data processors under GDPR/CCPA, requiring a data processing agreement. The licensee references the data processing ',
    `parent_licensee_id` BIGINT COMMENT 'Self-referencing FK on licensee (parent_licensee_id)',
    `regulatory_filing_id` BIGINT COMMENT 'Foreign key linking to compliance.regulatory_filing. Business justification: Licensees must hold valid regulatory filings (broadcast licenses, streaming service authorizations) to receive and distribute content. Licensee compliance verification and deal activation requires ref',
    `auto_renewal_enabled` BOOLEAN COMMENT 'Indicates whether the licensees contract includes automatic renewal provisions.',
    `blackout_rules_applicable` BOOLEAN COMMENT 'Indicates whether geographic or territorial blackout rules apply to this licensees distribution rights.',
    `business_address_line1` STRING COMMENT 'First line of the licensees primary business address.',
    `business_address_line2` STRING COMMENT 'Second line of the licensees primary business address for suite, floor, or building details.',
    `business_city` STRING COMMENT 'City where the licensees primary business office is located.',
    `business_country_code` STRING COMMENT 'Three-letter ISO country code for the licensees primary business location.',
    `business_postal_code` STRING COMMENT 'Postal or ZIP code of the licensees primary business address.',
    `business_state_province` STRING COMMENT 'State or province of the licensees primary business address.',
    `cdn_provider` STRING COMMENT 'Name of the CDN provider used by the licensee for content distribution and streaming.',
    `compliance_certification_date` DATE COMMENT 'Date of the most recent compliance certification or audit for the licensees operations.',
    `content_format_supported` STRING COMMENT 'Video and audio formats supported by the licensees distribution platform.',
    `contract_end_date` DATE COMMENT 'Date when the licensees broadcast rights agreement expires or terminates.',
    `contract_start_date` DATE COMMENT 'Date when the licensees broadcast rights agreement becomes effective.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the licensee record was first created in the system.',
    `credit_limit_amount` DECIMAL(18,2) COMMENT 'Maximum credit limit extended to the licensee for rights fees and services.',
    `distribution_channel` STRING COMMENT 'Primary distribution channel through which the licensee delivers content to end consumers.',
    `drm_policy_required` BOOLEAN COMMENT 'Indicates whether the licensee is required to implement DRM policies for content protection.',
    `is_active` BOOLEAN COMMENT 'Indicates whether the licensee record is currently active and available for operational use.',
    `licensee_code` STRING COMMENT 'Unique business identifier or code assigned to the licensee for operational reference and reporting.',
    `licensee_name` STRING COMMENT 'Full legal name of the licensee organization or entity holding broadcast rights.',
    `licensee_status` STRING COMMENT 'Current operational status of the licensee relationship.',
    `licensee_type` STRING COMMENT 'Classification of the licensee based on their distribution channel and business model.',
    `live_broadcast_enabled` BOOLEAN COMMENT 'Indicates whether the licensee is authorized to broadcast live events and programming.',
    `max_concurrent_streams` STRING COMMENT 'Maximum number of concurrent streams allowed under the licensees distribution agreement.',
    `modified_by` STRING COMMENT 'User identifier or name of the person who last modified the licensee record.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when the licensee record was last modified or updated.',
    `notes` STRING COMMENT 'Additional notes, comments, or special instructions related to the licensee relationship.',
    `parent_company_name` STRING COMMENT 'Name of the parent organization or holding company that owns or controls the licensee.',
    `payment_currency_code` STRING COMMENT 'Three-letter ISO currency code for financial transactions with the licensee.',
    `payment_terms_days` STRING COMMENT 'Standard payment terms in days for invoices issued to the licensee.',
    `ppv_enabled` BOOLEAN COMMENT 'Indicates whether the licensee is authorized to offer pay-per-view event packages.',
    `primary_contact_email` STRING COMMENT 'Email address of the primary business contact for licensee communications and coordination.',
    `primary_contact_name` STRING COMMENT 'Full name of the primary business contact person at the licensee organization.',
    `primary_contact_phone` STRING COMMENT 'Primary phone number for reaching the licensees business contact.',
    `renewal_notice_days` STRING COMMENT 'Number of days advance notice required for contract renewal or termination decisions.',
    `replay_content_enabled` BOOLEAN COMMENT 'Indicates whether the licensee is authorized to distribute replay or on-demand content.',
    `streaming_protocol` STRING COMMENT 'Primary streaming protocol used by the licensee for content delivery.',
    `subscriber_count` BIGINT COMMENT 'Total number of subscribers or viewers reached by the licensees distribution platform.',
    `tax_identification_number` STRING COMMENT 'Tax identification number or employer identification number for the licensee entity.',
    `territory_coverage` STRING COMMENT 'Geographic territories or regions covered by the licensees broadcast rights.',
    `created_by` STRING COMMENT 'User identifier or name of the person who created the licensee record.',
    CONSTRAINT pk_licensee PRIMARY KEY(`licensee_id`)
) COMMENT 'Master reference table for licensee. Referenced by licensee_id.';

